  category TEXT NOT NULL,
  description TEXT NOT NULL,
  source TEXT,
  source_ref TEXT,
  weight INTEGER DEFAULT 1,
  occurred_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
