-- ──────────────────────────────────────────────────────────────────────
-- 20260424120000_dori_action_confirmations.sql
-- ──────────────────────────────────────────────────────────────────────

-- Per-action-type confirmation preferences for the Dori assistant.
-- Lets each user decide whether Dori should ask for acknowledgment before
-- creating, editing, or deleting anything on their behalf (and override
-- that decision per module). Also tracks where a pending action came from
-- so the Telegram bot can ping the right chat when approval arrives.

ALTER TABLE public.proactive_settings
  ADD COLUMN IF NOT EXISTS require_action_confirmation boolean NOT NULL DEFAULT true,
  ADD COLUMN IF NOT EXISTS confirm_creates boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS confirm_updates boolean NOT NULL DEFAULT true,
  ADD COLUMN IF NOT EXISTS confirm_deletes boolean NOT NULL DEFAULT true,
  -- Per-entity overrides: { "task": { "delete": false }, "contract": { "create": true } }
  ADD COLUMN IF NOT EXISTS confirmation_overrides jsonb NOT NULL DEFAULT '{}'::jsonb;

COMMENT ON COLUMN public.proactive_settings.require_action_confirmation IS
  'Master toggle. When false, Dori auto-executes every action without asking.';

COMMENT ON COLUMN public.proactive_settings.confirm_creates IS
  'If true, Dori asks before creating (adding) anything.';

COMMENT ON COLUMN public.proactive_settings.confirm_updates IS
  'If true, Dori asks before editing any existing item.';

COMMENT ON COLUMN public.proactive_settings.confirm_deletes IS
  'If true, Dori asks before deleting any item.';

COMMENT ON COLUMN public.proactive_settings.confirmation_overrides IS
  'Per-module overrides of confirm_creates/updates/deletes, shape: {"<entity>":{"create":bool,"update":bool,"delete":bool}}';

ALTER TABLE public.auto_actions_log
  ADD COLUMN IF NOT EXISTS source text NOT NULL DEFAULT 'web',
  ADD COLUMN IF NOT EXISTS source_ref text;

COMMENT ON COLUMN public.auto_actions_log.source IS
  'Surface that queued the action: "web" | "tg_private" | "tg_family" | "voice" | "proactive".';

COMMENT ON COLUMN public.auto_actions_log.source_ref IS
  'Surface-specific reference (e.g. Telegram chat_id) so the originating surface can be notified on approval/rejection.';

CREATE INDEX IF NOT EXISTS auto_actions_log_user_status_created_idx
  ON public.auto_actions_log (user_id, status, created_at DESC);

-- ──────────────────────────────────────────────────────────────────────
-- 20260424180000_dori_telegram_richer_ux.sql
-- ──────────────────────────────────────────────────────────────────────

-- Richer Telegram assistant UX: action TTL, undo window, tracked mutations.

-- 1) Give queued actions an explicit expiry so a user ignoring a confirmation
--    doesn't leave ghost rows forever. The Telegram/web surfaces refuse to
--    execute expired entries and hide them from the inbox.
ALTER TABLE public.auto_actions_log
  ADD COLUMN IF NOT EXISTS expires_at timestamptz;

-- Back-fill: anything currently pending gets 24h from its creation.
UPDATE public.auto_actions_log
   SET expires_at = created_at + interval '24 hours'
 WHERE expires_at IS NULL;

COMMENT ON COLUMN public.auto_actions_log.expires_at IS
  'When a pending action should stop being actionable. NULL for legacy rows; new rows default to created_at + 24h.';

CREATE INDEX IF NOT EXISTS auto_actions_log_pending_expiry_idx
  ON public.auto_actions_log (user_id, status, expires_at DESC)
  WHERE status = 'pending';

-- 2) Record every mutation Dori executes so we can offer a one-tap undo for
--    a short window after the fact. Rows older than 5 minutes are never
--    shown as undoable, and the row is deleted the first time it is used.
CREATE TABLE IF NOT EXISTS public.dori_undo_log (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id uuid NOT NULL,
  -- 'create' | 'update' | 'delete' | 'complete'
  op text NOT NULL,
  entity_type text NOT NULL,
  entity_id text,                        -- row id in the target table when available
  label text NOT NULL,                   -- human-readable, e.g. "Delete task: Buy milk"
  -- Full inverse tool-XML, when we can reconstruct one. NULL means "not undoable"
  -- (e.g. irreversible external side effects).
  inverse_tool_xml text,
  -- Snapshot of the affected row(s) BEFORE the mutation, for restoring deletes / updates.
  snapshot jsonb,
  source text NOT NULL DEFAULT 'web',
  source_ref text,
  expires_at timestamptz NOT NULL DEFAULT (now() + interval '5 minutes'),
  created_at timestamptz NOT NULL DEFAULT now(),
  consumed_at timestamptz
);

CREATE INDEX IF NOT EXISTS dori_undo_log_user_recent_idx
  ON public.dori_undo_log (user_id, created_at DESC)
  WHERE consumed_at IS NULL;

COMMENT ON TABLE public.dori_undo_log IS
  'Short-lived record of each mutation Dori performed so the user can undo it via an inline button or /undo within a few minutes.';

-- ──────────────────────────────────────────────────────────────────────
-- 20260424210000_workspaces_foundation.sql
-- ──────────────────────────────────────────────────────────────────────

-- Workspaces = startup / team spaces. Each user can belong to any number of
-- workspaces, with a role. Existing personal data stays personal by keeping
-- workspace_id NULL. Everything we surface through the assistant can be
-- scoped to the user's active workspace via the same mechanism.
--
-- The existing `family_agent_groups` / `telegram_group_links` tables stay
-- intact so family-mode continues to work unchanged alongside workspaces.

CREATE TABLE IF NOT EXISTS public.workspaces (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  owner_id uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  name text NOT NULL,
  slug text,                              -- optional; lowercased handle for mentions
  description text,
  icon text,                              -- emoji or short code, e.g. "🚀"
  archived boolean NOT NULL DEFAULT false,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now(),
  CONSTRAINT workspaces_name_nonempty CHECK (length(trim(name)) > 0),
  CONSTRAINT workspaces_slug_fmt CHECK (slug IS NULL OR slug ~ '^[a-z0-9][a-z0-9_-]{1,39}$')
);

CREATE UNIQUE INDEX IF NOT EXISTS workspaces_slug_lower_idx ON public.workspaces (lower(slug)) WHERE slug IS NOT NULL;

CREATE TABLE IF NOT EXISTS public.workspace_members (
  workspace_id uuid NOT NULL REFERENCES public.workspaces(id) ON DELETE CASCADE,
  user_id uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  role text NOT NULL DEFAULT 'member',
  display_name text,                      -- overrides profile name for this workspace
  invited_by uuid REFERENCES public.users(id),
  invited_at timestamptz NOT NULL DEFAULT now(),
  joined_at timestamptz,
  PRIMARY KEY (workspace_id, user_id),
  CONSTRAINT workspace_members_role_chk CHECK (role IN ('owner', 'admin', 'member', 'viewer'))
);

CREATE INDEX IF NOT EXISTS workspace_members_user_idx ON public.workspace_members (user_id);

-- Invite codes the workspace owner/admin can generate + share. Join-by-code is
-- much easier than setting up email invites end-to-end.
CREATE TABLE IF NOT EXISTS public.workspace_invite_codes (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  workspace_id uuid NOT NULL REFERENCES public.workspaces(id) ON DELETE CASCADE,
  code text NOT NULL UNIQUE,
  role text NOT NULL DEFAULT 'member',
  created_by uuid NOT NULL REFERENCES public.users(id),
  max_uses integer,                       -- NULL = unlimited
  uses integer NOT NULL DEFAULT 0,
  expires_at timestamptz,
  revoked_at timestamptz,
  created_at timestamptz NOT NULL DEFAULT now(),
  CONSTRAINT workspace_invite_codes_role_chk CHECK (role IN ('admin', 'member', 'viewer'))
);

CREATE INDEX IF NOT EXISTS workspace_invite_codes_ws_idx ON public.workspace_invite_codes (workspace_id);

-- Links a Telegram group chat to a workspace, mirroring how family_agent_groups
-- handles households. A chat can only be linked to one workspace at a time.
CREATE TABLE IF NOT EXISTS public.workspace_telegram_links (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  workspace_id uuid NOT NULL REFERENCES public.workspaces(id) ON DELETE CASCADE,
  chat_id bigint NOT NULL UNIQUE,
  title text,
  link_code text,
  link_code_expires_at timestamptz,
  is_active boolean NOT NULL DEFAULT false,
  linked_at timestamptz,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS workspace_telegram_links_ws_idx ON public.workspace_telegram_links (workspace_id);

-- ── Add workspace_id / assignee_id to the core collaborative tables. ───────
-- Keeping columns nullable means existing "personal" data continues to work
-- without any backfill.
ALTER TABLE public.tasks
  ADD COLUMN IF NOT EXISTS workspace_id uuid REFERENCES public.workspaces(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS assignee_id uuid REFERENCES public.users(id) ON DELETE SET NULL;

ALTER TABLE public.events
  ADD COLUMN IF NOT EXISTS workspace_id uuid REFERENCES public.workspaces(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS assignee_id uuid REFERENCES public.users(id) ON DELETE SET NULL;

ALTER TABLE public.notes
  ADD COLUMN IF NOT EXISTS workspace_id uuid REFERENCES public.workspaces(id) ON DELETE SET NULL;

ALTER TABLE public.projects
  ADD COLUMN IF NOT EXISTS workspace_id uuid REFERENCES public.workspaces(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS tasks_workspace_idx     ON public.tasks     (workspace_id) WHERE workspace_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS tasks_assignee_idx      ON public.tasks     (assignee_id)  WHERE assignee_id  IS NOT NULL;

CREATE INDEX IF NOT EXISTS events_workspace_idx    ON public.events    (workspace_id) WHERE workspace_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS events_assignee_idx     ON public.events    (assignee_id)  WHERE assignee_id  IS NOT NULL;

CREATE INDEX IF NOT EXISTS notes_workspace_idx     ON public.notes     (workspace_id) WHERE workspace_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS projects_workspace_idx  ON public.projects  (workspace_id) WHERE workspace_id IS NOT NULL;

-- Helper: is the calling user a member of a workspace?
CREATE OR REPLACE FUNCTION public.is_workspace_member(ws uuid)
RETURNS boolean
LANGUAGE sql SECURITY DEFINER STABLE
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.workspace_members
     WHERE workspace_id = ws AND user_id = NULL /* TODO(auth-migration): was auth.uid() */
  );
$$;

CREATE OR REPLACE FUNCTION public.workspace_role(ws uuid)
RETURNS text
LANGUAGE sql SECURITY DEFINER STABLE
AS $$
  SELECT role FROM public.workspace_members
   WHERE workspace_id = ws AND user_id = NULL /* TODO(auth-migration): was auth.uid() */
   LIMIT 1;
$$;

-- Auto-add the creator as owner when a workspace is inserted.
CREATE OR REPLACE FUNCTION public.add_owner_to_new_workspace()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  INSERT INTO public.workspace_members (workspace_id, user_id, role, invited_by, invited_at, joined_at)
  VALUES (NEW.id, NEW.owner_id, 'owner', NEW.owner_id, now(), now())
  ON CONFLICT DO NOTHING;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS workspaces_add_owner ON public.workspaces;

CREATE OR REPLACE TRIGGER workspaces_add_owner
  AFTER INSERT ON public.workspaces
  FOR EACH ROW EXECUTE FUNCTION public.add_owner_to_new_workspace();

-- updated_at auto-touch on workspaces
CREATE OR REPLACE FUNCTION public.touch_workspace_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN NEW.updated_at = now(); RETURN NEW; END;
$$;

DROP TRIGGER IF EXISTS workspaces_touch_updated ON public.workspaces;

CREATE OR REPLACE TRIGGER workspaces_touch_updated
  BEFORE UPDATE ON public.workspaces
  FOR EACH ROW EXECUTE FUNCTION public.touch_workspace_updated_at();

-- ──────────────────────────────────────────────────────────────────────
-- 20260424230000_workspace_invite_atomic_increment.sql
-- ──────────────────────────────────────────────────────────────────────

-- Atomic increment + exhaustion guard for workspace invite codes.
-- Using this RPC from workspace-join avoids the read-modify-write race
-- where two users who join simultaneously can both see uses=0 and both
-- succeed past a max_uses=1 cap.

CREATE OR REPLACE FUNCTION public.increment_workspace_invite_uses(p_id uuid)
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_code public.workspace_invite_codes;
  v_claimed boolean;
BEGIN
  -- Row lock for the duration of the transaction so concurrent callers
  -- serialize through here.
  SELECT * INTO v_code FROM public.workspace_invite_codes
   WHERE id = p_id FOR UPDATE;

  IF NOT FOUND THEN RETURN false; END IF;
  IF v_code.revoked_at IS NOT NULL THEN RETURN false; END IF;
  IF v_code.expires_at IS NOT NULL AND v_code.expires_at < now() THEN RETURN false; END IF;
  IF v_code.max_uses IS NOT NULL AND v_code.uses >= v_code.max_uses THEN RETURN false; END IF;

  UPDATE public.workspace_invite_codes
     SET uses = uses + 1
   WHERE id = p_id;

  RETURN true;
END;
$$;

-- ──────────────────────────────────────────────────────────────────────
-- 20260425000000_dori_quiet_and_onboarding.sql
-- ──────────────────────────────────────────────────────────────────────

-- Proactive-quiet + onboarding-checklist settings.
--
-- Focus mode: user can silence Dori for a bounded window (/focus 2h).
-- Event suppression: default on, skip nudges while a meeting is in progress.
-- Onboarding checklist: tracked on proactive_settings so we can dismiss
-- the dashboard card without resetting the main onboarding flag.

ALTER TABLE public.proactive_settings
  ADD COLUMN IF NOT EXISTS focus_mode_until timestamptz,
  ADD COLUMN IF NOT EXISTS suppress_during_events boolean NOT NULL DEFAULT true,
  ADD COLUMN IF NOT EXISTS onboarding_checklist_dismissed boolean NOT NULL DEFAULT false;

COMMENT ON COLUMN public.proactive_settings.focus_mode_until IS
  'If in the future, Dori suppresses every proactive channel until this instant. Set via /focus.';

COMMENT ON COLUMN public.proactive_settings.suppress_during_events IS
  'When true, skip proactive notifications while a calendar event is in progress.';

COMMENT ON COLUMN public.proactive_settings.onboarding_checklist_dismissed IS
  'True once the dashboard Getting Started checklist has been closed for good.';

CREATE INDEX IF NOT EXISTS proactive_settings_focus_mode_idx
  ON public.proactive_settings (user_id)
  WHERE focus_mode_until IS NOT NULL;

-- ──────────────────────────────────────────────────────────────────────
-- 20260425000001_user_location_settings.sql
-- ──────────────────────────────────────────────────────────────────────

-- User location and local settings
-- Stores user's home location for prayer times and weather

CREATE TABLE IF NOT EXISTS public.user_location_settings (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL UNIQUE REFERENCES public.users(id) ON DELETE CASCADE,

  -- Location information
  city text NOT NULL DEFAULT 'Berlin',
  country text NOT NULL DEFAULT 'Germany',
  latitude decimal(10, 8),
  longitude decimal(11, 8),
  timezone text NOT NULL DEFAULT 'Europe/Berlin',

  -- Weather preferences
  show_weather boolean NOT NULL DEFAULT true,
  temperature_unit text NOT NULL DEFAULT 'celsius', -- 'celsius' | 'fahrenheit'

  -- Prayer calculation method
  prayer_calculation_method integer NOT NULL DEFAULT 2, -- 2 = ISNA (can be changed by user)

  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX idx_user_location_settings_user_id ON public.user_location_settings(user_id);

CREATE OR REPLACE TRIGGER update_user_location_settings_updated_at
  BEFORE UPDATE ON public.user_location_settings
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ──────────────────────────────────────────────────────────────────────
-- 20260425120000_team_polish_chunk_b.sql
-- ──────────────────────────────────────────────────────────────────────

-- Chunk B of the second top-10 arc: team-collaboration polish.
--
-- 1) telegram_links gets an active_workspace_id so a user in a 1:1 chat
--    can /workspace <name> to scope the next N commands. No fk — the
--    id may point to a workspace the user has since left; the poll
--    handler re-verifies membership on each use.
-- 2) task_comments: threaded discussion on tasks. workspace_id is
--    denormalized from the parent task via trigger so the realtime
--    hook can filter server-side and RLS doesn't have to join.
-- 3) REPLICA IDENTITY FULL on the workspace-realtime tables so DELETE
--    payloads actually contain user_id / workspace_id (default replica
--    identity returns only primary-key fields on delete, which would
--    defeat the "skip self" check in the realtime hook).

ALTER TABLE public.telegram_links
  ADD COLUMN IF NOT EXISTS active_workspace_id uuid;

COMMENT ON COLUMN public.telegram_links.active_workspace_id IS
  'Private-chat scope: when set, subsequent AI tool calls from this Telegram user go into this workspace. /workspace off to clear.';

CREATE TABLE IF NOT EXISTS public.task_comments (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  task_id uuid NOT NULL REFERENCES public.tasks(id) ON DELETE CASCADE,
  -- Nullable because ON DELETE SET NULL needs it. We prefer keeping
  -- the comment (as "deleted user") over losing the audit trail.
  author_id uuid REFERENCES public.users(id) ON DELETE SET NULL,
  -- Denormalized from the parent task so RLS + realtime filters don't
  -- need a join. Populated via trigger on INSERT (and re-populated on
  -- task workspace moves, which are rare).
  workspace_id uuid REFERENCES public.workspaces(id) ON DELETE SET NULL,
  body text NOT NULL,
  source text NOT NULL DEFAULT 'web',
  created_at timestamptz NOT NULL DEFAULT now(),
  CONSTRAINT task_comments_body_nonempty CHECK (length(trim(body)) > 0)
);

CREATE INDEX IF NOT EXISTS task_comments_task_created_idx
  ON public.task_comments (task_id, created_at DESC);

CREATE INDEX IF NOT EXISTS task_comments_workspace_idx
  ON public.task_comments (workspace_id) WHERE workspace_id IS NOT NULL;

-- Auto-fill workspace_id from the parent task on insert.
CREATE OR REPLACE FUNCTION public.task_comments_fill_workspace()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  IF NEW.workspace_id IS NULL THEN
    SELECT workspace_id INTO NEW.workspace_id FROM public.tasks WHERE id = NEW.task_id;
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS task_comments_fill_workspace_trg ON public.task_comments;

CREATE OR REPLACE TRIGGER task_comments_fill_workspace_trg
  BEFORE INSERT ON public.task_comments
  FOR EACH ROW EXECUTE FUNCTION public.task_comments_fill_workspace();

-- REPLICA IDENTITY FULL: emits full OLD rows on UPDATE/DELETE so the
-- realtime subscriber can read user_id / workspace_id / assignee_id
-- even on deletions. Without this the default (primary key only)
-- would make the "skip events I caused" check in
-- useWorkspaceRealtime misfire for deletes.
ALTER TABLE public.tasks          REPLICA IDENTITY FULL;

ALTER TABLE public.events         REPLICA IDENTITY FULL;

ALTER TABLE public.notes          REPLICA IDENTITY FULL;

ALTER TABLE public.task_comments  REPLICA IDENTITY FULL;

-- ──────────────────────────────────────────────────────────────────────
-- 20260425180000_memory_scoping_and_locale.sql
-- ──────────────────────────────────────────────────────────────────────

-- Chunk C of the second top-10 arc: Gmail send + per-workspace memory + locale.
--
-- 1) ai_memory.workspace_id: today memory is per-user only, so work and
--    personal facts pollute each other. When a user has an active
--    workspace, new memories land in it and loadDoriIntelligence
--    filters the intelligence block by scope.
-- 2) profiles.locale: optional IANA-like tag ('en-US', 'de', 'fr-FR', …)
--    so the chat function can inject a "respond in {locale}" hint into
--    the system prompt and the TG TTS voice can pick a matching voice
--    code. Null = let Dori auto-detect.

ALTER TABLE public.ai_memory
  ADD COLUMN IF NOT EXISTS workspace_id uuid REFERENCES public.workspaces(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS ai_memory_workspace_idx
  ON public.ai_memory (user_id, workspace_id);

COMMENT ON COLUMN public.ai_memory.workspace_id IS
  'When set, the memory is scoped to this workspace. NULL = personal. The chat function filters intelligence by the active scope.';

-- Uniqueness has to include scope, otherwise a workspace memory with the
-- same key as a personal one would overwrite it via upsert. A partial
-- unique index on (user_id, key) WHERE workspace_id IS NULL and another
-- on (user_id, key, workspace_id) WHERE NOT NULL would work, but
-- PostgREST's on_conflict needs one column set it can point at, so we
-- use a STORED generated column that folds NULL into a sentinel uuid.
ALTER TABLE public.ai_memory
  ADD COLUMN IF NOT EXISTS workspace_scope uuid
  GENERATED ALWAYS AS (COALESCE(workspace_id, '00000000-0000-0000-0000-000000000000'::uuid)) STORED;

CREATE UNIQUE INDEX IF NOT EXISTS ai_memory_user_key_scope_uidx
  ON public.ai_memory (user_id, key, workspace_scope);

COMMENT ON COLUMN public.ai_memory.workspace_scope IS
  'Generated column: folds NULL workspace_id into a sentinel uuid so a single unique index covers both personal and workspace scopes.';

ALTER TABLE public.profiles
  ADD COLUMN IF NOT EXISTS locale text;

COMMENT ON COLUMN public.profiles.locale IS
  'IANA-like locale tag (e.g. "en-US", "de", "fr-FR"). NULL lets Dori auto-detect from the user''s messages.';

-- ──────────────────────────────────────────────────────────────────────
-- 20260425200000_islamic_notifications.sql
-- ──────────────────────────────────────────────────────────────────────

-- Islamic event and hadith Telegram notifications
-- Stores user preferences for Islamic reminders (holidays, daily hadiths, prayer times)

CREATE TABLE IF NOT EXISTS public.islamic_notification_settings (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL UNIQUE REFERENCES public.users(id) ON DELETE CASCADE,

  -- Islamic event reminders (Eid, Ramadan, etc.)
  events_enabled boolean NOT NULL DEFAULT true,
  events_hours_before integer NOT NULL DEFAULT 24, -- Notify 24 hours before
  events_send_time text DEFAULT '08:00', -- HH:MM format, user's local time

  -- Daily hadith delivery
  daily_hadith_enabled boolean NOT NULL DEFAULT true,
  daily_hadith_time text DEFAULT '07:00', -- HH:MM format, user's local time
  hadith_source_preference text DEFAULT 'mixed', -- 'mixed' | 'bukhari' | 'muslim' | 'tirmidhi' | 'abudawud'

  -- Prayer time reminders
  prayer_reminders_enabled boolean NOT NULL DEFAULT true,
  prayer_reminder_minutes_before integer NOT NULL DEFAULT 5, -- Notify 5 min before
  prayer_reminders_for_all_five boolean NOT NULL DEFAULT true,
  prayer_reminders_selected jsonb DEFAULT '["Fajr", "Dhuhr", "Asr", "Maghrib", "Isha"]'::jsonb, -- Array of prayer names

  -- Language preference for notifications
  notification_language text DEFAULT 'en', -- 'en' | 'ar' | etc

  -- Timezone (important for scheduling notifications)
  timezone text DEFAULT 'UTC',

  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX idx_islamic_notification_settings_user_id ON public.islamic_notification_settings(user_id);

CREATE OR REPLACE TRIGGER update_islamic_notification_settings_updated_at
  BEFORE UPDATE ON public.islamic_notification_settings
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- Table to track which Islamic events have been notified (prevent duplicate sends)
CREATE TABLE IF NOT EXISTS public.islamic_event_notifications_sent (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  event_name text NOT NULL,
  event_date date NOT NULL,
  sent_at timestamptz NOT NULL DEFAULT now(),

  UNIQUE(user_id, event_name, event_date)
);

CREATE INDEX idx_islamic_event_notifications_sent_user_date ON public.islamic_event_notifications_sent(user_id, event_date);

-- Service role only (for cron jobs)

-- Table to track daily hadith delivery (prevent resending the same hadith)
CREATE TABLE IF NOT EXISTS public.islamic_daily_hadith_sent (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  hadith_id integer NOT NULL,
  sent_date date NOT NULL,
  sent_at timestamptz NOT NULL DEFAULT now(),

  UNIQUE(user_id, sent_date)
);

CREATE INDEX idx_islamic_daily_hadith_sent_user_date ON public.islamic_daily_hadith_sent(user_id, sent_date);

-- Service role only (for cron jobs)

-- ──────────────────────────────────────────────────────────────────────
-- 20260425230000_assistant_intelligence_uplift.sql
-- ──────────────────────────────────────────────────────────────────────

-- Assistant intelligence uplift.
--
-- Six pieces, one migration so they ship together:
--   1. pgvector extension + dori_semantic_memories — RAG over notes,
--      episodic memories, completed tasks, and chat turns. The chat
--      function retrieves top-k by cosine similarity per turn instead
--      of dumping a fixed snapshot.
--   2. dori_conversation_state — short-term cross-turn state (open
--      intent, pending confirmations, last referenced entity ids) so
--      multi-turn flows like "reschedule that" survive context refetches.
--   3. dori_task_stats — rolling per-user completion stats (median
--      lead time, slip rate, preferred hour-of-day per category) used
--      by both the learned-preferences rollup and the predictive
--      proactive scorer.
--   4. dori_intent_routing — log of specialist routing decisions
--      (general/health/family/meeting/finance) for debugging and
--      offline evaluation.
--   5. match_semantic_memories() — cosine-similarity RPC used by the
--      chat function. Wraps the IVFFlat lookup with the user_id filter
--      and an optional workspace scope.
--   6. dori_slip_risk view — joins open tasks with task_stats to expose
--      a 0-1 risk score the proactive-assistant can prioritise on.
--
-- All tables are user-scoped with RLS. Service role bypasses for the
-- background rollup + embedding workers.

-- ============================================================
-- 1. pgvector
-- ============================================================
CREATE EXTENSION IF NOT EXISTS vector;

CREATE TABLE IF NOT EXISTS public.dori_semantic_memories (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  workspace_id UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
  source TEXT NOT NULL CHECK (source IN (
    'note', 'episodic', 'task_completed', 'event_past',
    'chat_turn', 'memory', 'contact', 'manual'
  )),
  source_ref TEXT,
  content TEXT NOT NULL,
  -- 768-dim covers both Gemini text-embedding-004 and a downscaled
  -- OpenAI text-embedding-3-small (1536 → 768 via Matryoshka). Pick
  -- one dimension and stick to it; mixing dims would corrupt search.
  embedding vector(768),
  metadata JSONB DEFAULT '{}'::jsonb,
  importance NUMERIC DEFAULT 0.5 CHECK (importance >= 0 AND importance <= 1),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (user_id, source, source_ref)
);

-- HNSW (not IVFFlat) because:
--   1. RAG datasets are *dynamic* — new chat turns and notes land
--      every minute. IVFFlat needs the index trained on a
--      representative sample, then degrades as the data drifts and
--      requires periodic REINDEX. HNSW supports incremental writes
--      with no maintenance.
--   2. Recall vs. speed: HNSW has better recall at the same query
--      latency for our size class (~10k–1M rows/user).
--   3. Cosine because embeddings are L2-normalised by the embedding
--      provider, so cosine ≈ dot product ranks identically but is
--      invariant to scale drift between embedder versions.
-- m=16 / ef_construction=64 are the pgvector defaults — fine for our
-- workload. Raise ef_construction (build cost) for higher recall.
CREATE INDEX IF NOT EXISTS dori_semantic_memories_embedding_idx
  ON public.dori_semantic_memories USING hnsw (embedding vector_cosine_ops);

CREATE INDEX IF NOT EXISTS dori_semantic_memories_user_recent_idx
  ON public.dori_semantic_memories (user_id, created_at DESC);

CREATE INDEX IF NOT EXISTS dori_semantic_memories_workspace_idx
  ON public.dori_semantic_memories (user_id, workspace_id, created_at DESC);

CREATE OR REPLACE TRIGGER update_dori_semantic_memories_updated_at
  BEFORE UPDATE ON public.dori_semantic_memories
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- Cosine-similarity search RPC. Service-role calls bypass RLS but we
-- always pass p_user_id so the WHERE clause locks results to the
-- caller; never expose this RPC to the anon key.
CREATE OR REPLACE FUNCTION public.match_semantic_memories(
  p_user_id UUID,
  p_query_embedding vector(768),
  p_workspace_id UUID DEFAULT NULL,
  p_match_count INT DEFAULT 8,
  p_min_similarity NUMERIC DEFAULT 0.65
)
RETURNS TABLE (
  id UUID,
  source TEXT,
  source_ref TEXT,
  content TEXT,
  metadata JSONB,
  importance NUMERIC,
  created_at TIMESTAMPTZ,
  similarity NUMERIC
)
LANGUAGE sql
STABLE
AS $$
  SELECT
    m.id,
    m.source,
    m.source_ref,
    m.content,
    m.metadata,
    m.importance,
    m.created_at,
    1 - (m.embedding <=> p_query_embedding) AS similarity
  FROM public.dori_semantic_memories m
  WHERE m.user_id = p_user_id
    AND m.embedding IS NOT NULL
    AND (
      p_workspace_id IS NULL
        AND m.workspace_id IS NULL
      OR p_workspace_id IS NOT NULL
        AND (m.workspace_id = p_workspace_id OR m.workspace_id IS NULL)
    )
    AND 1 - (m.embedding <=> p_query_embedding) >= p_min_similarity
  ORDER BY m.embedding <=> p_query_embedding
  LIMIT p_match_count;
$$;

-- ============================================================
-- 2. Cross-turn conversation state
-- ============================================================
-- One active state row per (user, channel). Multi-turn flows write
-- their open intent + pending entity references here so the next turn
-- can resolve "do it" / "the meeting" / "him" without re-asking.
CREATE TABLE IF NOT EXISTS public.dori_conversation_state (
  user_id UUID NOT NULL,
  channel TEXT NOT NULL CHECK (channel IN ('web', 'tg_private', 'tg_family', 'voice')),
  -- Open intent (e.g. 'awaiting_plan_approval', 'choose_among_candidates',
  -- 'confirm_email_send'). NULL = no pending state.
  open_intent TEXT,
  -- The proposed plan / candidates / draft, kept verbatim so the next
  -- turn can re-emit it on confirmation.
  pending_payload JSONB DEFAULT '{}'::jsonb,
  -- Most recently referenced concrete entities (task_id, event_id,
  -- contact_id, …). The chat function uses this to resolve pronouns.
  recent_entities JSONB DEFAULT '[]'::jsonb,
  -- Specialist the router last selected — used to keep follow-up
  -- turns inside the same specialist mindset unless the topic shifts.
  active_specialist TEXT,
  expires_at TIMESTAMPTZ NOT NULL DEFAULT (now() + interval '1 hour'),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (user_id, channel)
);

CREATE INDEX IF NOT EXISTS dori_conversation_state_expiry_idx
  ON public.dori_conversation_state (expires_at)
  WHERE open_intent IS NOT NULL;

-- ============================================================
-- 3. Per-user completion stats (rolled up nightly)
-- ============================================================
-- Aggregated from `tasks`. The rollup job rewrites the row, so we
-- keep a single row per (user_id, category, hour_bucket).
CREATE TABLE IF NOT EXISTS public.dori_task_stats (
  user_id UUID NOT NULL,
  category TEXT NOT NULL,
  -- Bucketed hour-of-day (0-23) for slot-preference learning. -1 is
  -- the sentinel for "all hours" (category-level aggregate). NOT NULL
  -- so the PRIMARY KEY collapses correctly — Postgres treats NULL as
  -- distinct in unique constraints, which would let dupes through.
  hour_bucket SMALLINT NOT NULL CHECK (hour_bucket BETWEEN -1 AND 23),
  -- Sample size for confidence weighting.
  sample_size INTEGER NOT NULL DEFAULT 0,
  -- Median lead time in hours (created_at → completed_at). Used for
  -- realistic due-date suggestions.
  median_lead_hours NUMERIC,
  -- Fraction of tasks completed by their due_date. 1.0 = always on
  -- time, 0.0 = always slips.
  on_time_rate NUMERIC,
  -- Median delay in hours past due_date (only counts tasks that
  -- actually slipped, so this is unbiased by sometimes-on-time tasks).
  median_slip_hours NUMERIC,
  computed_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (user_id, category, hour_bucket)
);

CREATE INDEX IF NOT EXISTS dori_task_stats_user_idx
  ON public.dori_task_stats (user_id, computed_at DESC);

-- Only the service role rolls these up. No user-facing INSERT policy.

-- ============================================================
-- 4. Intent routing log
-- ============================================================
CREATE TABLE IF NOT EXISTS public.dori_intent_routing (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  channel TEXT,
  user_message_excerpt TEXT,
  classified_specialist TEXT NOT NULL,
  confidence NUMERIC,
  used_specialist TEXT,
  metadata JSONB DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS dori_intent_routing_user_idx
  ON public.dori_intent_routing (user_id, created_at DESC);

-- ============================================================
-- 5. Slip-risk view
-- ============================================================
-- Each open task gets a 0-1 score. The proactive-assistant joins on
-- this to surface "this is going to slip" reminders BEFORE the due
-- date, instead of only after it's already overdue.
CREATE OR REPLACE VIEW public.dori_slip_risk AS
SELECT
  t.id AS task_id,
  t.user_id,
  t.workspace_id,
  t.title,
  t.category,
  t.priority,
  t.due_date,
  COALESCE(s.on_time_rate, 0.7) AS user_on_time_rate,
  COALESCE(s.median_lead_hours, 24) AS expected_lead_hours,
  -- Risk = (1 - on_time_rate) scaled by how close the due date is.
  -- A task due in <12h with a chronically late user → risk near 1.
  -- A task due in 7d for a reliable user → risk near 0.
  CASE
    WHEN t.due_date IS NULL THEN 0
    WHEN t.due_date < now() THEN 1.0
    ELSE LEAST(
      1.0,
      (1.0 - COALESCE(s.on_time_rate, 0.7)) *
      GREATEST(0.0, 1.0 - EXTRACT(EPOCH FROM (t.due_date - now())) / (COALESCE(s.median_lead_hours, 24) * 3600))
      + CASE WHEN t.priority = 'high' THEN 0.15 ELSE 0 END
    )
  END AS slip_risk
FROM public.tasks t
LEFT JOIN public.dori_task_stats s
  ON s.user_id = t.user_id
  AND s.category = t.category
  AND s.hour_bucket = -1
WHERE t.completed = false
  AND t.trashed = false;

COMMENT ON VIEW public.dori_slip_risk IS
  'Per-open-task slip-risk score (0-1). Computed from the user''s historical on-time rate and the time-to-due. The proactive-assistant uses this to surface at-risk tasks BEFORE they go overdue.';

-- ──────────────────────────────────────────────────────────────────────
-- 20260426120000_persistent_memory_kg.sql
-- ──────────────────────────────────────────────────────────────────────

-- Persistent memory + knowledge graph.
--
-- Adds an entity / provenance / forget layer on top of the existing
-- `dori_semantic_memories`, `ai_memory`, and `episodic_memories` tables.
-- Goal: durable cross-module memory that the user can audit and prune.
--
-- Four tables + a handful of RPCs:
--   1. kg_entities       — canonical people / projects / places /
--                          organizations / topics, deduped per user.
--   2. kg_mentions       — many-to-many link from a memory row (in any
--                          source table) to one or more entities.
--   3. memory_provenance — derivation chain. Lets the UI answer "why
--                          do you remember this?" and lets the forget
--                          machinery cascade upstream.
--   4. memory_redactions — audit log of every user-initiated forget,
--                          system-applied retention, and cascade.
--
-- All four are user-scoped with RLS. Service role inserts on behalf of
-- the extraction worker (kg-extract edge fn).

-- ============================================================
-- 1. Entities
-- ============================================================
CREATE TABLE IF NOT EXISTS public.kg_entities (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  workspace_id UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
  -- Coarse type. Keep the list short — fine-grained typing belongs in metadata.
  kind TEXT NOT NULL CHECK (kind IN (
    'person', 'project', 'place', 'organization',
    'topic', 'product', 'event'
  )),
  name TEXT NOT NULL,
  -- lower(trim(name)) — used as the dedup key. We keep `name` separate
  -- so the display form preserves capitalisation ("John" vs. "john").
  name_normalized TEXT NOT NULL,
  aliases TEXT[] NOT NULL DEFAULT '{}',
  -- Cross-references to concrete rows in other tables.
  --   { "contact_id": "...", "workspace_id": "...", "task_id": "..." }
  external_refs JSONB NOT NULL DEFAULT '{}'::jsonb,
  description TEXT,
  importance NUMERIC NOT NULL DEFAULT 0.5
    CHECK (importance >= 0 AND importance <= 1),
  -- Maintained by triggers on kg_mentions so the UI can sort by it
  -- without an aggregate query per row.
  mention_count INTEGER NOT NULL DEFAULT 0,
  last_mentioned_at TIMESTAMPTZ,
  -- Soft-delete: forgetting an entity sets this and cascades to mentions.
  redacted_at TIMESTAMPTZ,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (user_id, kind, name_normalized)
);

CREATE INDEX IF NOT EXISTS kg_entities_user_kind_idx
  ON public.kg_entities (user_id, kind, last_mentioned_at DESC NULLS LAST)
  WHERE redacted_at IS NULL;

CREATE INDEX IF NOT EXISTS kg_entities_user_recent_idx
  ON public.kg_entities (user_id, last_mentioned_at DESC NULLS LAST)
  WHERE redacted_at IS NULL;

CREATE INDEX IF NOT EXISTS kg_entities_aliases_gin
  ON public.kg_entities USING GIN (aliases);

CREATE OR REPLACE TRIGGER update_kg_entities_updated_at
  BEFORE UPDATE ON public.kg_entities
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ============================================================
-- 2. Mentions (entity ↔ memory-row link)
-- ============================================================
-- A single memory row can mention N entities; an entity can be
-- referenced by N memory rows. The (source_kind, source_id) pair is a
-- polymorphic FK — we don't enforce it because the underlying tables
-- live in different schemas (semantic vs. episodic vs. ai_memory) and
-- some sources are external strings (chat turns).
CREATE TABLE IF NOT EXISTS public.kg_mentions (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  entity_id UUID NOT NULL REFERENCES public.kg_entities(id) ON DELETE CASCADE,
  source_kind TEXT NOT NULL CHECK (source_kind IN (
    'semantic', 'episodic', 'ai_memory', 'task',
    'event', 'note', 'contact', 'chat'
  )),
  source_id TEXT NOT NULL,
  -- 0..1, how central this entity is to the source row. Used to weight
  -- entity-aware recall — a casual mention shouldn't outrank a primary
  -- subject just because it's recent.
  salience NUMERIC NOT NULL DEFAULT 0.5
    CHECK (salience >= 0 AND salience <= 1),
  excerpt TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (user_id, entity_id, source_kind, source_id)
);

CREATE INDEX IF NOT EXISTS kg_mentions_entity_idx
  ON public.kg_mentions (entity_id, created_at DESC);

CREATE INDEX IF NOT EXISTS kg_mentions_source_idx
  ON public.kg_mentions (user_id, source_kind, source_id);

CREATE INDEX IF NOT EXISTS kg_mentions_user_recent_idx
  ON public.kg_mentions (user_id, created_at DESC);

-- Keep entity counters in sync. Cheap because it's per-row, and we'd
-- otherwise need a sub-query in every list view.
CREATE OR REPLACE FUNCTION public.kg_mentions_after_insert()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  UPDATE public.kg_entities
     SET mention_count = mention_count + 1,
         last_mentioned_at = GREATEST(COALESCE(last_mentioned_at, NEW.created_at), NEW.created_at)
   WHERE id = NEW.entity_id;
  RETURN NEW;
END;
$$;

CREATE OR REPLACE FUNCTION public.kg_mentions_after_delete()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  UPDATE public.kg_entities
     SET mention_count = GREATEST(0, mention_count - 1)
   WHERE id = OLD.entity_id;
  RETURN OLD;
END;
$$;

DROP TRIGGER IF EXISTS kg_mentions_count_ins ON public.kg_mentions;

CREATE OR REPLACE TRIGGER kg_mentions_count_ins
  AFTER INSERT ON public.kg_mentions
  FOR EACH ROW EXECUTE FUNCTION public.kg_mentions_after_insert();

DROP TRIGGER IF EXISTS kg_mentions_count_del ON public.kg_mentions;

CREATE OR REPLACE TRIGGER kg_mentions_count_del
  AFTER DELETE ON public.kg_mentions
  FOR EACH ROW EXECUTE FUNCTION public.kg_mentions_after_delete();

-- ============================================================
-- 3. Provenance
-- ============================================================
-- "Why do you remember this?" Each derived memory row points back at
-- the raw input it came from (an email, a chat turn, a task, …). The
-- forget machinery walks this in reverse.
CREATE TABLE IF NOT EXISTS public.memory_provenance (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  target_kind TEXT NOT NULL CHECK (target_kind IN (
    'semantic', 'episodic', 'ai_memory', 'kg_entity'
  )),
  target_id UUID NOT NULL,
  source_kind TEXT NOT NULL,
  source_id TEXT NOT NULL,
  transformation TEXT NOT NULL CHECK (transformation IN (
    'extracted', 'summarized', 'aggregated',
    'inferred', 'manual', 'imported'
  )),
  model TEXT,
  confidence NUMERIC NOT NULL DEFAULT 0.7
    CHECK (confidence >= 0 AND confidence <= 1),
  notes TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS memory_provenance_target_idx
  ON public.memory_provenance (user_id, target_kind, target_id);

CREATE INDEX IF NOT EXISTS memory_provenance_source_idx
  ON public.memory_provenance (user_id, source_kind, source_id);

-- ============================================================
-- 4. Redactions (forget audit)
-- ============================================================
-- Every "forget this" action lands here. Mostly insert-only — the
-- audit log itself is never trimmed by the forget machinery, so a user
-- can always answer "what have I asked the assistant to forget?".
CREATE TABLE IF NOT EXISTS public.memory_redactions (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  target_kind TEXT NOT NULL CHECK (target_kind IN (
    'semantic', 'episodic', 'ai_memory', 'kg_entity',
    'all_for_entity', 'all_for_topic', 'all_for_date_range'
  )),
  target_id TEXT,
  scope JSONB NOT NULL DEFAULT '{}'::jsonb,
  reason TEXT,
  cascaded_count INTEGER NOT NULL DEFAULT 0,
  applied_by TEXT NOT NULL DEFAULT 'user'
    CHECK (applied_by IN ('user', 'system')),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS memory_redactions_user_idx
  ON public.memory_redactions (user_id, created_at DESC);

-- ============================================================
-- 5. RPC: upsert an entity (dedup by user + kind + normalized name)
-- ============================================================
-- Returns the row's id. If a row already exists, merges aliases and
-- bumps importance toward the new value (smoothed average).
CREATE OR REPLACE FUNCTION public.kg_upsert_entity(
  p_user_id UUID,
  p_kind TEXT,
  p_name TEXT,
  p_aliases TEXT[] DEFAULT '{}',
  p_external_refs JSONB DEFAULT '{}'::jsonb,
  p_workspace_id UUID DEFAULT NULL,
  p_importance NUMERIC DEFAULT 0.5,
  p_description TEXT DEFAULT NULL
)
RETURNS UUID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_id UUID;
  v_norm TEXT;
BEGIN
  v_norm := lower(trim(p_name));
  IF v_norm = '' OR v_norm IS NULL THEN
    RAISE EXCEPTION 'kg_upsert_entity: empty name';
  END IF;

  INSERT INTO public.kg_entities (
    user_id, workspace_id, kind, name, name_normalized,
    aliases, external_refs, importance, description
  ) VALUES (
    p_user_id, p_workspace_id, p_kind, p_name, v_norm,
    COALESCE(p_aliases, '{}'), COALESCE(p_external_refs, '{}'::jsonb),
    LEAST(1, GREATEST(0, COALESCE(p_importance, 0.5))),
    p_description
  )
  ON CONFLICT (user_id, kind, name_normalized) DO UPDATE SET
    aliases = (
      SELECT array_agg(DISTINCT a)
        FROM unnest(public.kg_entities.aliases || COALESCE(EXCLUDED.aliases, '{}')) AS a
       WHERE a IS NOT NULL AND a <> ''
    ),
    external_refs = public.kg_entities.external_refs || COALESCE(EXCLUDED.external_refs, '{}'::jsonb),
    importance = LEAST(1, (public.kg_entities.importance * 0.7) + (EXCLUDED.importance * 0.3)),
    description = COALESCE(EXCLUDED.description, public.kg_entities.description),
    redacted_at = NULL,
    updated_at = now()
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;

-- ============================================================
-- 6. RPC: link a memory row to an entity (idempotent)
-- ============================================================
CREATE OR REPLACE FUNCTION public.kg_link_mention(
  p_user_id UUID,
  p_entity_id UUID,
  p_source_kind TEXT,
  p_source_id TEXT,
  p_salience NUMERIC DEFAULT 0.5,
  p_excerpt TEXT DEFAULT NULL
)
RETURNS UUID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_id UUID;
BEGIN
  INSERT INTO public.kg_mentions (
    user_id, entity_id, source_kind, source_id, salience, excerpt
  ) VALUES (
    p_user_id, p_entity_id, p_source_kind, p_source_id,
    LEAST(1, GREATEST(0, COALESCE(p_salience, 0.5))),
    LEFT(COALESCE(p_excerpt, ''), 600)
  )
  ON CONFLICT (user_id, entity_id, source_kind, source_id) DO UPDATE SET
    salience = LEAST(1, (public.kg_mentions.salience * 0.7) + (EXCLUDED.salience * 0.3)),
    excerpt = COALESCE(EXCLUDED.excerpt, public.kg_mentions.excerpt)
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$$;

-- ============================================================
-- 7. RPC: entity neighborhood (co-occurrence)
-- ============================================================
-- Two entities are "neighbors" when they share a memory row. Returns
-- the top N co-occurring entities by overlap count.
CREATE OR REPLACE FUNCTION public.kg_neighborhood(
  p_user_id UUID,
  p_entity_id UUID,
  p_limit INT DEFAULT 12
)
RETURNS TABLE (
  entity_id UUID,
  name TEXT,
  kind TEXT,
  shared_mentions BIGINT,
  last_co_mention TIMESTAMPTZ
)
LANGUAGE sql
STABLE
AS $$
  WITH src AS (
    SELECT source_kind, source_id, created_at
      FROM public.kg_mentions
     WHERE user_id = p_user_id AND entity_id = p_entity_id
  )
  SELECT
    e.id AS entity_id,
    e.name,
    e.kind,
    COUNT(*) AS shared_mentions,
    MAX(m.created_at) AS last_co_mention
  FROM public.kg_mentions m
  JOIN src ON src.source_kind = m.source_kind AND src.source_id = m.source_id
  JOIN public.kg_entities e ON e.id = m.entity_id
  WHERE m.user_id = p_user_id
    AND m.entity_id <> p_entity_id
    AND e.redacted_at IS NULL
  GROUP BY e.id, e.name, e.kind
  ORDER BY shared_mentions DESC, last_co_mention DESC
  LIMIT p_limit;
$$;

-- ============================================================
-- 8. RPC: top entities (for the dashboard list)
-- ============================================================
CREATE OR REPLACE FUNCTION public.kg_top_entities(
  p_user_id UUID,
  p_limit INT DEFAULT 50,
  p_kinds TEXT[] DEFAULT NULL
)
RETURNS TABLE (
  id UUID,
  kind TEXT,
  name TEXT,
  description TEXT,
  importance NUMERIC,
  mention_count INTEGER,
  last_mentioned_at TIMESTAMPTZ,
  external_refs JSONB
)
LANGUAGE sql
STABLE
AS $$
  SELECT
    e.id, e.kind, e.name, e.description,
    e.importance, e.mention_count, e.last_mentioned_at, e.external_refs
  FROM public.kg_entities e
  WHERE e.user_id = p_user_id
    AND e.redacted_at IS NULL
    AND (p_kinds IS NULL OR e.kind = ANY(p_kinds))
  ORDER BY
    e.last_mentioned_at DESC NULLS LAST,
    e.mention_count DESC
  LIMIT p_limit;
$$;

-- ============================================================
-- 9. RPC: cascading forget
-- ============================================================
-- One entry point, three cascade modes:
--   * 'semantic'     → soft-delete the dori_semantic_memories row.
--   * 'episodic'     → delete the episodic_memories row.
--   * 'ai_memory'    → set is_active=false on ai_memory.
--   * 'kg_entity'    → set redacted_at on the entity AND drop its
--                      mentions, AND null-out matching aliases on
--                      semantic rows that referenced it.
--
-- Always logs to memory_redactions so the user has an undo trail.
CREATE OR REPLACE FUNCTION public.forget_memory_target(
  p_user_id UUID,
  p_target_kind TEXT,
  p_target_id TEXT,
  p_reason TEXT DEFAULT NULL
)
RETURNS INT
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_count INT := 0;
  v_uuid UUID;
BEGIN
  IF p_target_kind = 'semantic' THEN
    v_uuid := p_target_id::uuid;
    DELETE FROM public.dori_semantic_memories
     WHERE user_id = p_user_id AND id = v_uuid;
    GET DIAGNOSTICS v_count = ROW_COUNT;
    DELETE FROM public.kg_mentions
     WHERE user_id = p_user_id
       AND source_kind = 'semantic'
       AND source_id = v_uuid::text;

  ELSIF p_target_kind = 'episodic' THEN
    v_uuid := p_target_id::uuid;
    DELETE FROM public.episodic_memories
     WHERE user_id = p_user_id AND id = v_uuid;
    GET DIAGNOSTICS v_count = ROW_COUNT;
    DELETE FROM public.kg_mentions
     WHERE user_id = p_user_id
       AND source_kind = 'episodic'
       AND source_id = v_uuid::text;

  ELSIF p_target_kind = 'ai_memory' THEN
    v_uuid := p_target_id::uuid;
    UPDATE public.ai_memory
       SET is_active = false, updated_at = now()
     WHERE user_id = p_user_id AND id = v_uuid;
    GET DIAGNOSTICS v_count = ROW_COUNT;
    DELETE FROM public.kg_mentions
     WHERE user_id = p_user_id
       AND source_kind = 'ai_memory'
       AND source_id = v_uuid::text;

  ELSIF p_target_kind = 'kg_entity' THEN
    v_uuid := p_target_id::uuid;
    UPDATE public.kg_entities
       SET redacted_at = now(), updated_at = now()
     WHERE user_id = p_user_id AND id = v_uuid;
    GET DIAGNOSTICS v_count = ROW_COUNT;
    -- Cascade through every memory row this entity was attached to.
    -- We delete mentions (cheap) but DON'T auto-delete the underlying
    -- memory rows — those may also be about other entities. The user
    -- can opt into a deeper sweep via the UI.
    DELETE FROM public.kg_mentions
     WHERE user_id = p_user_id AND entity_id = v_uuid;

  ELSE
    RAISE EXCEPTION 'forget_memory_target: unknown target_kind %', p_target_kind;
  END IF;

  INSERT INTO public.memory_redactions (
    user_id, target_kind, target_id, reason, cascaded_count, applied_by
  ) VALUES (
    p_user_id, p_target_kind, p_target_id, p_reason, v_count, 'user'
  );

  RETURN v_count;
END;
$$;

-- ============================================================
-- 10. View: unified memory audit feed
-- ============================================================
-- One read for the audit UI — no five separate queries on the client.
-- Each row is a memory item with normalized fields. Order is
-- (created_at DESC) so the UI can paginate it directly.
CREATE OR REPLACE VIEW public.memory_audit_feed AS
SELECT
  'semantic'::text AS source_kind,
  m.id::text AS source_id,
  m.user_id,
  m.workspace_id,
  m.source AS sub_kind,
  m.content AS content,
  NULL::text AS title,
  m.metadata,
  m.importance,
  NULL::numeric AS confidence,
  m.created_at,
  m.updated_at
FROM public.dori_semantic_memories m
UNION ALL
SELECT
  'episodic'::text,
  e.id::text,
  e.user_id,
  NULL::uuid,
  COALESCE(e.source, 'episodic'),
  COALESCE(e.summary, e.title),
  e.title,
  jsonb_build_object('people', e.people, 'tags', e.tags, 'location', e.location, 'occurred_on', e.occurred_on),
  e.importance,
  NULL::numeric,
  e.created_at,
  e.updated_at
FROM public.episodic_memories e
UNION ALL
SELECT
  'ai_memory'::text,
  a.id::text,
  a.user_id,
  a.workspace_id,
  a.memory_type,
  a.value,
  a.key,
  jsonb_build_object('category', a.category, 'context', a.context, 'source', a.source),
  NULL::numeric,
  a.confidence,
  a.created_at,
  a.updated_at
FROM public.ai_memory a
WHERE a.is_active = true;

COMMENT ON VIEW public.memory_audit_feed IS
  'Unified read-only feed of every memory item the assistant holds for a user. Drives the Memory & Privacy dashboard. Honors RLS via the underlying tables.';

-- ============================================================
-- 11. Counter rebuild (one-shot, for any pre-existing entities)
-- ============================================================
-- mention_count + last_mentioned_at are maintained by the trigger
-- going forward, but if backfill ever inserts mentions out-of-band
-- this RPC re-syncs the cache.
CREATE OR REPLACE FUNCTION public.kg_resync_entity_counters(p_user_id UUID)
RETURNS INT
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_updated INT;
BEGIN
  WITH agg AS (
    SELECT entity_id,
           COUNT(*) AS cnt,
           MAX(created_at) AS last_seen
      FROM public.kg_mentions
     WHERE user_id = p_user_id
     GROUP BY entity_id
  )
  UPDATE public.kg_entities e
     SET mention_count = COALESCE(agg.cnt, 0),
         last_mentioned_at = agg.last_seen,
         updated_at = now()
    FROM agg
   WHERE e.user_id = p_user_id
     AND e.id = agg.entity_id;
  GET DIAGNOSTICS v_updated = ROW_COUNT;
  RETURN v_updated;
END;
$$;

-- ──────────────────────────────────────────────────────────────────────
-- 20260426170000_dori_action_plans.sql
-- ──────────────────────────────────────────────────────────────────────

-- Durable agentic execution loop.
--
-- Adds first-class persistence to the multi-step "propose_plan" flow that
-- the chat function emits today. Until now, the plan lived only in
-- conversation state and died on refresh; from this migration on, plans
-- are real rows that survive refreshes, expose progress to the user,
-- and gate every step behind explicit approval.
--
-- Two new tables:
--   1. dori_action_plans — one row per plan. Tracks lifecycle (draft →
--                          awaiting_confirm → running → completed/aborted/failed).
--   2. dori_plan_steps   — ordered steps inside a plan. Each step holds
--                          the goal text the executor will hand to the
--                          chat agent, plus its own status + result +
--                          undo back-reference.
--
-- Plus an additive ALTER on auto_actions_log: a plan_id + plan_step_id
-- back-reference so single-action audit rows can be associated with the
-- plan they came from. This lets the existing AgentActionInbox and
-- Telegram inline confirm flow keep working unchanged for one-off
-- actions while the new PlansPanel handles plan-aware UX.

-- ============================================================
-- 1. Plans
-- ============================================================
CREATE TABLE IF NOT EXISTS public.dori_action_plans (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  workspace_id UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
  -- Originating channel — useful for routing follow-up confirms back to
  -- the same surface (Telegram inline keyboard vs. web sheet).
  channel TEXT NOT NULL DEFAULT 'web'
    CHECK (channel IN ('web', 'tg_private', 'tg_family', 'voice', 'auto_pilot')),
  source TEXT NOT NULL DEFAULT 'chat'
    CHECK (source IN ('chat', 'auto_pilot', 'manual', 'recap')),
  title TEXT NOT NULL,
  description TEXT,
  -- Lifecycle:
  --   draft           → not yet shown to the user.
  --   awaiting_confirm → user has the plan; first step is gated.
  --   running         → a step is executing right now.
  --   paused          → user explicitly paused; resumable.
  --   completed       → all steps succeeded (or skipped).
  --   aborted         → user aborted mid-flight.
  --   failed          → a step failed and `auto_continue_on_fail` was off.
  status TEXT NOT NULL DEFAULT 'awaiting_confirm'
    CHECK (status IN (
      'draft', 'awaiting_confirm', 'running',
      'paused', 'completed', 'aborted', 'failed'
    )),
  step_count INTEGER NOT NULL DEFAULT 0,
  completed_step_count INTEGER NOT NULL DEFAULT 0,
  -- Index of the next step to act on (idx in dori_plan_steps). NULL
  -- means "no more pending steps".
  current_step_idx INTEGER,
  -- Plans expire after a long but bounded window so abandoned ones
  -- don't accumulate in the inbox forever. The chat function clears
  -- expired ones lazily.
  expires_at TIMESTAMPTZ NOT NULL DEFAULT (now() + interval '7 days'),
  completed_at TIMESTAMPTZ,
  aborted_at TIMESTAMPTZ,
  -- Free-form metadata (specialist that proposed, originating message
  -- id, …). Don't put PII or tool args here — those go in steps.
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS dori_action_plans_user_active_idx
  ON public.dori_action_plans (user_id, updated_at DESC)
  WHERE status NOT IN ('completed', 'aborted', 'failed');

CREATE INDEX IF NOT EXISTS dori_action_plans_user_recent_idx
  ON public.dori_action_plans (user_id, created_at DESC);

CREATE INDEX IF NOT EXISTS dori_action_plans_expiry_idx
  ON public.dori_action_plans (expires_at)
  WHERE status NOT IN ('completed', 'aborted', 'failed');

CREATE OR REPLACE TRIGGER update_dori_action_plans_updated_at
  BEFORE UPDATE ON public.dori_action_plans
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ============================================================
-- 2. Plan steps
-- ============================================================
CREATE TABLE IF NOT EXISTS public.dori_plan_steps (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  plan_id UUID NOT NULL REFERENCES public.dori_action_plans(id) ON DELETE CASCADE,
  user_id UUID NOT NULL,
  -- 0-based ordinal. Unique within a plan.
  idx INTEGER NOT NULL,
  title TEXT NOT NULL,
  -- Natural-language goal that the executor passes to the chat agent
  -- as "Now do: <description>". The agent picks the right tool. We
  -- specifically DON'T pre-bake tool_xml here so the executor can
  -- adapt to context it didn't have at plan-time (e.g. a contact id
  -- that became known after step 1).
  description TEXT,
  -- Optional pre-baked tool_xml. When present, the executor skips the
  -- agent round-trip and feeds it directly into chat's preformedToolText
  -- path. Useful for deterministic steps like "send this exact email".
  tool_hint TEXT,
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN (
      'pending', 'awaiting_confirm', 'running',
      'succeeded', 'failed', 'skipped', 'aborted'
    )),
  -- Per-step gating. Default true: every step requires explicit user
  -- approval. The auto_pilot caller can set false to chain trusted
  -- low-risk steps.
  requires_confirmation BOOLEAN NOT NULL DEFAULT true,
  result_summary TEXT,
  error_message TEXT,
  -- Back-reference into dori_undo_log so the UI can offer a per-step
  -- undo button without re-querying by entity_id.
  undo_log_id UUID,
  executed_at TIMESTAMPTZ,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (plan_id, idx)
);

CREATE INDEX IF NOT EXISTS dori_plan_steps_plan_idx
  ON public.dori_plan_steps (plan_id, idx);

CREATE INDEX IF NOT EXISTS dori_plan_steps_user_pending_idx
  ON public.dori_plan_steps (user_id, plan_id)
  WHERE status IN ('pending', 'awaiting_confirm', 'running');

CREATE OR REPLACE TRIGGER update_dori_plan_steps_updated_at
  BEFORE UPDATE ON public.dori_plan_steps
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ============================================================
-- 3. ALTER auto_actions_log: link to plan / step
-- ============================================================
-- One auto_actions_log row per executed step. The single-action approve
-- flow continues to work for non-plan actions (plan_id IS NULL).
ALTER TABLE public.auto_actions_log
  ADD COLUMN IF NOT EXISTS plan_id UUID
    REFERENCES public.dori_action_plans(id) ON DELETE SET NULL;

ALTER TABLE public.auto_actions_log
  ADD COLUMN IF NOT EXISTS plan_step_id UUID
    REFERENCES public.dori_plan_steps(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS auto_actions_log_plan_idx
  ON public.auto_actions_log (plan_id)
  WHERE plan_id IS NOT NULL;

-- ============================================================
-- 4. RPC: create a plan from a JSON spec
-- ============================================================
-- Atomic create: one plan row + N step rows. p_steps is a JSON array;
-- each element is { title, description?, tool_hint?, requires_confirmation? }.
CREATE OR REPLACE FUNCTION public.dori_create_plan(
  p_user_id UUID,
  p_title TEXT,
  p_description TEXT,
  p_steps JSONB,
  p_source TEXT DEFAULT 'chat',
  p_channel TEXT DEFAULT 'web',
  p_workspace_id UUID DEFAULT NULL,
  p_metadata JSONB DEFAULT '{}'::jsonb
)
RETURNS UUID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_plan_id UUID;
  v_step_count INTEGER;
  v_step JSONB;
  v_idx INTEGER := 0;
  v_title TEXT;
BEGIN
  IF jsonb_typeof(p_steps) <> 'array' THEN
    RAISE EXCEPTION 'dori_create_plan: p_steps must be a JSON array';
  END IF;
  v_step_count := jsonb_array_length(p_steps);
  IF v_step_count = 0 THEN
    RAISE EXCEPTION 'dori_create_plan: at least one step required';
  END IF;
  IF v_step_count > 25 THEN
    -- Defense in depth — keeps a runaway model from filling the table.
    RAISE EXCEPTION 'dori_create_plan: too many steps (max 25)';
  END IF;

  INSERT INTO public.dori_action_plans (
    user_id, workspace_id, channel, source, title, description,
    status, step_count, current_step_idx, metadata
  ) VALUES (
    p_user_id, p_workspace_id, p_channel, p_source,
    LEFT(p_title, 200), LEFT(COALESCE(p_description, ''), 1000),
    'awaiting_confirm', v_step_count, 0,
    COALESCE(p_metadata, '{}'::jsonb)
  )
  RETURNING id INTO v_plan_id;

  FOR v_step IN SELECT * FROM jsonb_array_elements(p_steps)
  LOOP
    v_title := COALESCE(v_step->>'title', 'Step ' || (v_idx + 1));
    INSERT INTO public.dori_plan_steps (
      plan_id, user_id, idx, title, description, tool_hint, requires_confirmation, metadata
    ) VALUES (
      v_plan_id, p_user_id, v_idx,
      LEFT(v_title, 200),
      LEFT(COALESCE(v_step->>'description', ''), 1000),
      v_step->>'tool_hint',
      COALESCE((v_step->>'requires_confirmation')::boolean, true),
      COALESCE(v_step->'metadata', '{}'::jsonb)
    );
    v_idx := v_idx + 1;
  END LOOP;

  RETURN v_plan_id;
END;
$$;

-- ============================================================
-- 5. RPC: cancel a plan
-- ============================================================
-- Sets the plan to 'aborted' and marks every still-open step as
-- 'aborted'. Idempotent — re-aborting a completed plan is a no-op.
CREATE OR REPLACE FUNCTION public.dori_cancel_plan(
  p_user_id UUID,
  p_plan_id UUID,
  p_reason TEXT DEFAULT NULL
)
RETURNS INTEGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_steps_changed INTEGER;
BEGIN
  UPDATE public.dori_action_plans
     SET status = 'aborted',
         aborted_at = now(),
         metadata = metadata || jsonb_build_object('abort_reason', p_reason),
         updated_at = now()
   WHERE id = p_plan_id
     AND user_id = p_user_id
     AND status NOT IN ('completed', 'aborted', 'failed');

  UPDATE public.dori_plan_steps
     SET status = 'aborted',
         updated_at = now()
   WHERE plan_id = p_plan_id
     AND user_id = p_user_id
     AND status IN ('pending', 'awaiting_confirm', 'running');
  GET DIAGNOSTICS v_steps_changed = ROW_COUNT;
  RETURN v_steps_changed;
END;
$$;

-- ============================================================
-- 6. RPC: skip current step
-- ============================================================
-- Marks the current pending/awaiting_confirm step as skipped, advances
-- the plan, and returns the new state JSON (so the caller can render
-- without a follow-up SELECT).
CREATE OR REPLACE FUNCTION public.dori_skip_current_step(
  p_user_id UUID,
  p_plan_id UUID,
  p_reason TEXT DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_step_id UUID;
  v_idx INTEGER;
  v_completed INTEGER;
  v_total INTEGER;
  v_next_idx INTEGER;
  v_plan_status TEXT;
BEGIN
  SELECT id, idx INTO v_step_id, v_idx
    FROM public.dori_plan_steps
   WHERE plan_id = p_plan_id
     AND user_id = p_user_id
     AND status IN ('pending', 'awaiting_confirm', 'running')
   ORDER BY idx
   LIMIT 1;

  IF v_step_id IS NULL THEN
    RETURN jsonb_build_object('skipped', false, 'reason', 'no pending step');
  END IF;

  UPDATE public.dori_plan_steps
     SET status = 'skipped',
         result_summary = COALESCE(p_reason, 'skipped by user'),
         executed_at = now(),
         updated_at = now()
   WHERE id = v_step_id;

  -- Recompute counters + figure out next step.
  SELECT COUNT(*) FILTER (
           WHERE status IN ('succeeded', 'skipped')
         ),
         COUNT(*),
         MIN(idx) FILTER (
           WHERE status IN ('pending', 'awaiting_confirm')
         )
    INTO v_completed, v_total, v_next_idx
    FROM public.dori_plan_steps
   WHERE plan_id = p_plan_id;

  v_plan_status := CASE
    WHEN v_next_idx IS NULL THEN 'completed'
    ELSE 'awaiting_confirm'
  END;

  UPDATE public.dori_action_plans
     SET completed_step_count = v_completed,
         current_step_idx = v_next_idx,
         status = v_plan_status,
         completed_at = CASE WHEN v_plan_status = 'completed' THEN now() ELSE NULL END,
         updated_at = now()
   WHERE id = p_plan_id;

  RETURN jsonb_build_object(
    'skipped', true,
    'step_id', v_step_id,
    'next_step_idx', v_next_idx,
    'plan_status', v_plan_status,
    'completed_step_count', v_completed,
    'total', v_total
  );
END;
$$;

-- ============================================================
-- 7. View: active plans for the inbox
-- ============================================================
CREATE OR REPLACE VIEW public.dori_active_plans AS
SELECT
  p.id,
  p.user_id,
  p.workspace_id,
  p.channel,
  p.source,
  p.title,
  p.description,
  p.status,
  p.step_count,
  p.completed_step_count,
  p.current_step_idx,
  p.expires_at,
  p.completed_at,
  p.aborted_at,
  p.metadata,
  p.created_at,
  p.updated_at,
  -- The "current" step row, embedded so the inbox can render the next
  -- action without a follow-up query per plan.
  (
    SELECT jsonb_build_object(
      'id', s.id,
      'idx', s.idx,
      'title', s.title,
      'description', s.description,
      'status', s.status,
      'requires_confirmation', s.requires_confirmation,
      'result_summary', s.result_summary,
      'error_message', s.error_message
    )
    FROM public.dori_plan_steps s
    WHERE s.plan_id = p.id
      AND s.idx = COALESCE(p.current_step_idx, 0)
    LIMIT 1
  ) AS current_step
FROM public.dori_action_plans p
WHERE p.status NOT IN ('completed', 'aborted', 'failed')
   OR p.updated_at > now() - interval '24 hours';

COMMENT ON VIEW public.dori_active_plans IS
  'Plans the inbox should surface. Includes anything still in flight, plus recently-finished plans for the last 24h so users can review what just happened.';

-- ──────────────────────────────────────────────────────────────────────
-- 20260426210000_meeting_bots.sql
-- ──────────────────────────────────────────────────────────────────────

-- Meeting copilot integration (MeetingBot service).
--
-- One row per bot scheduled / running / finished against a meeting URL.
-- The MeetingBot service does the heavy lifting (Zoom/Meet/Teams join,
-- recording, transcription, analysis); we persist the lifecycle here so
-- the user can:
--   - see what's joining, when, and why
--   - read the transcript + summary + action items after the call
--   - link a bot to an existing calendar `events` row (if scheduled
--     from there) so the meeting prep / follow-up tools can find it.
--
-- The actual bot id (from MeetingBot) lives in `external_bot_id`. Our
-- own primary key stays a UUID so foreign keys to local tasks /
-- workspaces stay portable.

CREATE TABLE IF NOT EXISTS public.meeting_bots (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  workspace_id UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
  -- Optional link to an existing calendar event row. Lets the calendar
  -- detail view show bot status alongside attendees.
  event_id UUID REFERENCES public.events(id) ON DELETE SET NULL,
  -- Opaque id returned by MeetingBot's POST /api/v1/bot. NULL until
  -- the create call comes back; if creation failed we still keep the
  -- row so the user has an audit trail.
  external_bot_id TEXT,
  meeting_url TEXT NOT NULL,
  -- Human label. We pre-fill from the linked event title if available.
  title TEXT,
  bot_name TEXT NOT NULL DEFAULT 'Notetaker',
  -- Lifecycle. Mirrors MeetingBot's terminal-state taxonomy plus a
  -- local 'pending' for "row created, external call hasn't returned
  -- yet" so a crashed schedule doesn't leave an orphan.
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN (
      'pending', 'scheduled', 'joining', 'in_call',
      'call_ended', 'transcript_ready', 'analysis_ready',
      'done', 'error', 'cancelled'
    )),
  -- ISO-8601 timestamp the user picked for join (NULL = "join now").
  join_at TIMESTAMPTZ,
  joined_at TIMESTAMPTZ,
  ended_at TIMESTAMPTZ,
  -- Bulky payload columns. JSONB so we can index later by speaker,
  -- topic, etc. without a schema change.
  transcript JSONB NOT NULL DEFAULT '[]'::jsonb,
  summary TEXT,
  key_points JSONB NOT NULL DEFAULT '[]'::jsonb,
  action_items JSONB NOT NULL DEFAULT '[]'::jsonb,
  decisions JSONB NOT NULL DEFAULT '[]'::jsonb,
  next_steps JSONB NOT NULL DEFAULT '[]'::jsonb,
  topics JSONB NOT NULL DEFAULT '[]'::jsonb,
  sentiment TEXT,
  -- Free-form: bot creation request, raw webhook payloads, MeetingBot's
  -- own per-platform meta. Useful for debugging without bloating the
  -- typed columns.
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  error_message TEXT,
  -- When auto-task creation runs, we set this so a re-delivery of the
  -- same webhook doesn't double-create tasks.
  tasks_created_at TIMESTAMPTZ,
  tasks_created_count INTEGER NOT NULL DEFAULT 0,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (user_id, external_bot_id)
);

CREATE INDEX IF NOT EXISTS meeting_bots_user_recent_idx
  ON public.meeting_bots (user_id, created_at DESC);

CREATE INDEX IF NOT EXISTS meeting_bots_user_active_idx
  ON public.meeting_bots (user_id, updated_at DESC)
  WHERE status NOT IN ('done', 'error', 'cancelled');

CREATE INDEX IF NOT EXISTS meeting_bots_event_idx
  ON public.meeting_bots (event_id)
  WHERE event_id IS NOT NULL;

CREATE OR REPLACE TRIGGER update_meeting_bots_updated_at
  BEFORE UPDATE ON public.meeting_bots
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ──────────────────────────────────────────────────────────────────────
-- 20260427000000_financial_os.sql
-- ──────────────────────────────────────────────────────────────────────

-- Financial OS: bank linking + sync.
--
-- Extends the existing financial_accounts / financial_transactions
-- schema with everything Plaid (and future providers like TrueLayer
-- or GoCardless) needs to keep the local rows in sync:
--
--   1. bank_connections — one row per linked Plaid Item. Holds the
--      access_token, institution metadata, and the cursor used by
--      /transactions/sync.
--   2. ALTER financial_accounts: external_id, source, mask, subtype.
--   3. ALTER financial_transactions: external_id, source, pending,
--      iso_currency_code, payment_channel, plaid_category_detailed
--      JSONB. UNIQUE (user_id, source, external_id) makes the sync
--      upsert idempotent.
--   4. subscription_audit — view that joins active contracts to
--      transactions by fuzzy merchant match. Closes the loop on the
--      detect-recurring-payments edge function: now you can see
--      "your last $14.99 Netflix charge hit on the 14th" alongside
--      the contract row.
--   5. finance_summary — month-to-date rollups per category + per
--      account, in one query for the dashboard.

-- ============================================================
-- 1. bank_connections
-- ============================================================
CREATE TABLE IF NOT EXISTS public.bank_connections (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  -- 'plaid' for now; 'truelayer' / 'gocardless' / etc. later. Keep
  -- the column generic so the same table holds every provider.
  provider TEXT NOT NULL DEFAULT 'plaid'
    CHECK (provider IN ('plaid', 'truelayer', 'gocardless', 'manual')),
  -- Plaid: item_id from /item/get. Other providers: their connection
  -- id. NULL for 'manual' (no upstream).
  external_item_id TEXT,
  -- Plaid: access_token (sk_live or sk_sandbox-prefixed). Stored at
  -- rest in plaintext — Supabase encrypts the column with the
  -- platform key, but if you're operating outside Supabase managed,
  -- wrap this in pgsodium or rotate it through Vault.
  access_token TEXT,
  institution_id TEXT,
  institution_name TEXT,
  -- One of: 'good' | 'reauth_required' | 'error' | 'disabled'. We
  -- bump it from the sync edge fn when Plaid returns ITEM_LOGIN_REQUIRED.
  status TEXT NOT NULL DEFAULT 'good'
    CHECK (status IN ('good', 'reauth_required', 'error', 'disabled')),
  -- Cursor returned by /transactions/sync — pass back on the next
  -- call to fetch only deltas. Empty string on first sync.
  sync_cursor TEXT NOT NULL DEFAULT '',
  last_synced_at TIMESTAMPTZ,
  last_error TEXT,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (user_id, provider, external_item_id)
);

CREATE INDEX IF NOT EXISTS bank_connections_user_idx
  ON public.bank_connections (user_id, created_at DESC);

CREATE INDEX IF NOT EXISTS bank_connections_user_active_idx
  ON public.bank_connections (user_id, status)
  WHERE status IN ('good', 'reauth_required');

CREATE OR REPLACE TRIGGER update_bank_connections_updated_at
  BEFORE UPDATE ON public.bank_connections
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ============================================================
-- 2. ALTER financial_accounts
-- ============================================================
ALTER TABLE public.financial_accounts
  ADD COLUMN IF NOT EXISTS source TEXT
    DEFAULT 'manual'
    CHECK (source IN ('plaid', 'truelayer', 'gocardless', 'manual', 'imported'));

ALTER TABLE public.financial_accounts
  ADD COLUMN IF NOT EXISTS external_id TEXT;

ALTER TABLE public.financial_accounts
  ADD COLUMN IF NOT EXISTS mask TEXT;

ALTER TABLE public.financial_accounts
  ADD COLUMN IF NOT EXISTS subtype TEXT;

ALTER TABLE public.financial_accounts
  ADD COLUMN IF NOT EXISTS bank_connection_id UUID
    REFERENCES public.bank_connections(id) ON DELETE SET NULL;

-- One Plaid account_id can only map to one of our rows per user.
-- Partial unique index because manual rows have NULL external_id and
-- aren't subject to dedup.
CREATE UNIQUE INDEX IF NOT EXISTS financial_accounts_external_uniq
  ON public.financial_accounts (user_id, source, external_id)
  WHERE external_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS financial_accounts_connection_idx
  ON public.financial_accounts (bank_connection_id)
  WHERE bank_connection_id IS NOT NULL;

-- ============================================================
-- 3. ALTER financial_transactions
-- ============================================================
ALTER TABLE public.financial_transactions
  ADD COLUMN IF NOT EXISTS source TEXT
    DEFAULT 'manual'
    CHECK (source IN ('plaid', 'truelayer', 'gocardless', 'manual', 'imported'));

ALTER TABLE public.financial_transactions
  ADD COLUMN IF NOT EXISTS external_id TEXT;

ALTER TABLE public.financial_transactions
  ADD COLUMN IF NOT EXISTS pending BOOLEAN NOT NULL DEFAULT false;

ALTER TABLE public.financial_transactions
  ADD COLUMN IF NOT EXISTS iso_currency_code TEXT;

ALTER TABLE public.financial_transactions
  ADD COLUMN IF NOT EXISTS payment_channel TEXT;

-- Plaid's "personal_finance_category" object: { primary, detailed,
-- confidence_level }. Stored verbatim so we don't lose detail.
ALTER TABLE public.financial_transactions
  ADD COLUMN IF NOT EXISTS plaid_category_detailed JSONB;

ALTER TABLE public.financial_transactions
  ADD COLUMN IF NOT EXISTS metadata JSONB NOT NULL DEFAULT '{}'::jsonb;

CREATE UNIQUE INDEX IF NOT EXISTS financial_transactions_external_uniq
  ON public.financial_transactions (user_id, source, external_id)
  WHERE external_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS financial_transactions_merchant_idx
  ON public.financial_transactions (user_id, lower(merchant))
  WHERE merchant IS NOT NULL;

-- ============================================================
-- 4. subscription_audit view
-- ============================================================
-- For each active contract, find the most recent transaction whose
-- merchant looks like the contract provider (case-insensitive
-- substring match either direction) and compute the days since the
-- last charge. The UI uses this to flag "your subscription is older
-- than the renewal cycle but you haven't been billed lately" or
-- "you cancelled but the bank still shows charges".
CREATE OR REPLACE VIEW public.subscription_audit AS
SELECT
  c.id AS contract_id,
  c.user_id,
  c.name AS contract_name,
  c.provider AS contract_provider,
  c.category AS contract_category,
  c.cost_amount AS expected_amount,
  c.cost_frequency AS expected_frequency,
  c.renewal_date,
  c.auto_renews,
  -- Most recent matched transaction. NULL if no merchant on file
  -- looks like this contract — useful "we never saw a charge" signal.
  last_match.tx_id AS last_transaction_id,
  last_match.tx_merchant AS last_transaction_merchant,
  last_match.tx_amount AS last_transaction_amount,
  last_match.tx_date AS last_transaction_date,
  CASE
    WHEN last_match.tx_date IS NULL THEN NULL
    ELSE (CURRENT_DATE - last_match.tx_date)
  END AS days_since_last_charge,
  -- Total charged in the trailing 90 days under the matched merchant.
  COALESCE(rolling.total_90d, 0) AS total_charged_90d,
  COALESCE(rolling.charge_count_90d, 0) AS charge_count_90d
FROM public.contracts c
LEFT JOIN LATERAL (
  SELECT
    t.id AS tx_id,
    t.merchant AS tx_merchant,
    t.amount AS tx_amount,
    t.occurred_on AS tx_date
  FROM public.financial_transactions t
  WHERE t.user_id = c.user_id
    AND t.merchant IS NOT NULL
    AND (
      lower(t.merchant) LIKE '%' || lower(coalesce(c.provider, '')) || '%'
      OR lower(coalesce(c.provider, '')) LIKE '%' || lower(t.merchant) || '%'
      OR lower(t.merchant) LIKE '%' || lower(c.name) || '%'
      OR lower(c.name) LIKE '%' || lower(t.merchant) || '%'
    )
  ORDER BY t.occurred_on DESC
  LIMIT 1
) AS last_match ON true
LEFT JOIN LATERAL (
  SELECT
    SUM(t.amount) AS total_90d,
    COUNT(*) AS charge_count_90d
  FROM public.financial_transactions t
  WHERE t.user_id = c.user_id
    AND t.merchant IS NOT NULL
    AND t.occurred_on >= CURRENT_DATE - INTERVAL '90 days'
    AND t.direction = 'expense'
    AND (
      lower(t.merchant) LIKE '%' || lower(coalesce(c.provider, '')) || '%'
      OR lower(coalesce(c.provider, '')) LIKE '%' || lower(t.merchant) || '%'
      OR lower(t.merchant) LIKE '%' || lower(c.name) || '%'
      OR lower(c.name) LIKE '%' || lower(t.merchant) || '%'
    )
) AS rolling ON true
WHERE c.is_active = true;

COMMENT ON VIEW public.subscription_audit IS
  'Joins active contracts to bank transactions via fuzzy merchant match. The dashboard uses it to surface "ghost" subscriptions (no recent charge but contract still active) and "still-charging" cancellations.';

-- ============================================================
-- 5. finance_summary view
-- ============================================================
CREATE OR REPLACE VIEW public.finance_summary AS
WITH month_bounds AS (
  SELECT
    NULL /* TODO(auth-migration): was auth.uid() */ AS user_id,
    date_trunc('month', CURRENT_DATE)::date AS m_start,
    (date_trunc('month', CURRENT_DATE) + interval '1 month - 1 day')::date AS m_end
),
spend AS (
  SELECT
    t.user_id,
    t.category,
    SUM(t.amount) FILTER (WHERE t.direction = 'expense') AS spent_mtd,
    SUM(t.amount) FILTER (WHERE t.direction = 'income')  AS earned_mtd
  FROM public.financial_transactions t
  WHERE t.occurred_on >= date_trunc('month', CURRENT_DATE)::date
  GROUP BY t.user_id, t.category
)
SELECT
  s.user_id,
  s.category,
  COALESCE(s.spent_mtd, 0) AS spent_mtd,
  COALESCE(s.earned_mtd, 0) AS earned_mtd,
  b.monthly_limit,
  CASE
    WHEN b.monthly_limit IS NULL OR b.monthly_limit = 0 THEN NULL
    ELSE LEAST(1.0, COALESCE(s.spent_mtd, 0) / b.monthly_limit)
  END AS pct_of_budget
FROM spend s
LEFT JOIN public.financial_budgets b
  ON b.user_id = s.user_id AND b.category = s.category;

COMMENT ON VIEW public.finance_summary IS
  'Per-category month-to-date spend + budget headroom. RLS-friendly: uses NULL /* TODO(auth-migration): was auth.uid() */ inside a CTE so the result auto-scopes.';

-- ──────────────────────────────────────────────────────────────────────
-- 20260427040000_travel_concierge.sql
-- ──────────────────────────────────────────────────────────────────────

-- Travel concierge: multi-leg itinerary + weather cache.
--
-- The trips / trip_bookings / packing_lists / country_essentials
-- schema already exists. This migration fills the gaps:
--
--   1. trip_segments     — ordered legs of a trip (depart → arrive,
--                          mode, duration). trip_bookings is for
--                          confirmation numbers; segments is for the
--                          itinerary the user actually walks through.
--   2. weather_snapshots — cached forecast lookups keyed by
--                          (lat, lon rounded, date). 6h TTL via
--                          updated_at; the weather-forecast edge fn
--                          serves from cache when fresh.
--   3. ALTER trips: lat/lon, timezone, weather_summary, packing_status.
--                   Lets the dashboard render a trip card without
--                   joining anything.
--   4. ALTER packing_lists: status field + computed counts via view.
--   5. trip_overview view: one query for the dashboard — trip + days
--                          until + packing progress + segment count.

-- ============================================================
-- 1. trip_segments
-- ============================================================
CREATE TABLE IF NOT EXISTS public.trip_segments (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  trip_id UUID NOT NULL REFERENCES public.trips(id) ON DELETE CASCADE,
  user_id UUID NOT NULL,
  -- 0-based ordinal within the trip. UNIQUE (trip_id, idx) keeps the
  -- itinerary sane.
  idx INTEGER NOT NULL,
  -- 'flight' | 'train' | 'bus' | 'car' | 'ferry' | 'hotel' | 'activity' | 'free'
  -- Hotels and activities slot into the same ordered list as transit
  -- so the UI can render "Day 2: train to Berlin → check in to hotel"
  -- without two queries.
  segment_type TEXT NOT NULL DEFAULT 'flight'
    CHECK (segment_type IN (
      'flight', 'train', 'bus', 'car', 'ferry',
      'hotel', 'activity', 'free'
    )),
  title TEXT NOT NULL,
  -- Locations. For transit, origin → destination. For hotel/activity,
  -- origin = destination.
  origin TEXT,
  origin_lat NUMERIC,
  origin_lon NUMERIC,
  destination TEXT,
  destination_lat NUMERIC,
  destination_lon NUMERIC,
  -- Times in the LOCAL timezone of the origin (for transit) or
  -- the destination (for hotel/activity). The UI converts as needed
  -- from `timezone`.
  start_time TIMESTAMPTZ,
  end_time TIMESTAMPTZ,
  timezone TEXT,
  provider TEXT,
  reference TEXT,                -- e.g. flight number, PNR, hotel name
  cost NUMERIC,
  currency TEXT,
  notes TEXT,
  -- Back-ref to trip_bookings if this segment is the same as a
  -- confirmation row. Lets the UI link "Segment 2: BA flight 123"
  -- to the boarding-pass document.
  booking_id UUID REFERENCES public.trip_bookings(id) ON DELETE SET NULL,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (trip_id, idx)
);

CREATE INDEX IF NOT EXISTS trip_segments_user_idx
  ON public.trip_segments (user_id, start_time);

CREATE INDEX IF NOT EXISTS trip_segments_trip_idx
  ON public.trip_segments (trip_id, idx);

CREATE OR REPLACE TRIGGER update_trip_segments_updated_at
  BEFORE UPDATE ON public.trip_segments
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ============================================================
-- 2. weather_snapshots
-- ============================================================
-- Cache of Open-Meteo forecast lookups. Key = (lat rounded to 0.1°,
-- lon rounded to 0.1°, date). 0.1° ≈ 11km — plenty for "should I
-- pack a coat" precision and gives us a high cache hit rate.
CREATE TABLE IF NOT EXISTS public.weather_snapshots (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  -- Rounded lat/lon — see comment above.
  lat_grid NUMERIC NOT NULL,
  lon_grid NUMERIC NOT NULL,
  date DATE NOT NULL,
  temp_min_c NUMERIC,
  temp_max_c NUMERIC,
  precipitation_mm NUMERIC,
  precipitation_probability NUMERIC,  -- 0..100
  wind_speed_max_kmh NUMERIC,
  weather_code INTEGER,                -- WMO code from Open-Meteo
  summary TEXT,                        -- human-readable single line
  fetched_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (lat_grid, lon_grid, date)
);

CREATE INDEX IF NOT EXISTS weather_snapshots_freshness_idx
  ON public.weather_snapshots (fetched_at DESC);

-- ============================================================
-- 3. ALTER trips: cached metadata so the dashboard avoids joins
-- ============================================================
ALTER TABLE public.trips
  ADD COLUMN IF NOT EXISTS destination_lat NUMERIC;

ALTER TABLE public.trips
  ADD COLUMN IF NOT EXISTS destination_lon NUMERIC;

ALTER TABLE public.trips
  ADD COLUMN IF NOT EXISTS timezone TEXT;

ALTER TABLE public.trips
  ADD COLUMN IF NOT EXISTS weather_summary TEXT;

ALTER TABLE public.trips
  ADD COLUMN IF NOT EXISTS weather_refreshed_at TIMESTAMPTZ;

-- ============================================================
-- 4. ALTER packing_lists: per-list status
-- ============================================================
-- The items JSONB array can hold { name, packed: bool, category? }.
-- We add a top-level status for "we generated this AI-first" vs
-- "user added manually" so the UI can show the right badge.
ALTER TABLE public.packing_lists
  ADD COLUMN IF NOT EXISTS source TEXT
    DEFAULT 'manual'
    CHECK (source IN ('manual', 'ai_generated', 'imported'));

ALTER TABLE public.packing_lists
  ADD COLUMN IF NOT EXISTS generated_at TIMESTAMPTZ;

ALTER TABLE public.packing_lists
  ADD COLUMN IF NOT EXISTS metadata JSONB NOT NULL DEFAULT '{}'::jsonb;

-- ============================================================
-- 5. trip_overview view
-- ============================================================
-- Single-row-per-trip read for the /travel page and chat context:
-- packing progress, segment count, days until departure, etc.
CREATE OR REPLACE VIEW public.trip_overview AS
SELECT
  t.id AS trip_id,
  t.user_id,
  t.title,
  t.destination,
  t.destination_country,
  t.destination_lat,
  t.destination_lon,
  t.timezone,
  t.start_date,
  t.end_date,
  t.purpose,
  t.status,
  t.weather_summary,
  t.weather_refreshed_at,
  -- Days until departure. Negative if already started.
  (t.start_date - CURRENT_DATE) AS days_until_departure,
  (t.end_date - t.start_date) AS trip_length_days,
  -- Segment + booking + packing rollups.
  COALESCE(seg.segment_count, 0) AS segment_count,
  COALESCE(book.booking_count, 0) AS booking_count,
  COALESCE(pack.list_count, 0) AS packing_list_count,
  COALESCE(pack.total_items, 0) AS packing_total_items,
  COALESCE(pack.packed_items, 0) AS packing_packed_items,
  CASE
    WHEN COALESCE(pack.total_items, 0) = 0 THEN NULL
    ELSE ROUND((pack.packed_items::numeric / pack.total_items) * 100)
  END AS packing_pct
FROM public.trips t
LEFT JOIN LATERAL (
  SELECT COUNT(*) AS segment_count
    FROM public.trip_segments s
   WHERE s.trip_id = t.id
) seg ON true
LEFT JOIN LATERAL (
  SELECT COUNT(*) AS booking_count
    FROM public.trip_bookings b
   WHERE b.trip_id = t.id
) book ON true
LEFT JOIN LATERAL (
  SELECT
    COUNT(*) AS list_count,
    COALESCE(SUM(jsonb_array_length(items)), 0) AS total_items,
    COALESCE(SUM((
      SELECT COUNT(*) FROM jsonb_array_elements(items) AS itm
       WHERE COALESCE((itm->>'packed')::boolean, false) = true
    )), 0) AS packed_items
    FROM public.packing_lists pl
   WHERE pl.trip_id = t.id
     AND jsonb_typeof(items) = 'array'
) pack ON true;

COMMENT ON VIEW public.trip_overview IS
  'One row per trip with cached counters (segments, bookings, packing progress) and days_until_departure. Drives the /travel dashboard and chat context for "when is my next trip" queries.';

-- ──────────────────────────────────────────────────────────────────────
-- 20260427090000_vision_captures.sql
-- ──────────────────────────────────────────────────────────────────────

-- Vision-first capture.
--
-- One pipeline that turns a photo into the right downstream entity:
--   receipt          → financial_transactions + receipts row
--   business_card    → user_contacts row
--   medication       → personal_medications row
--   whiteboard       → notes row with extracted text
--   label            → translation displayed only (no entity)
--   document         → notes row with OCR text (or later: contract via existing scan-contract)
--
-- The vision_captures table tracks the lifecycle so a user can:
--   - see every photo they took and what was extracted
--   - re-classify or re-extract when the model gets it wrong
--   - audit which downstream rows came from which photo

CREATE TABLE IF NOT EXISTS public.vision_captures (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  workspace_id UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
  -- Storage info. We reuse the existing chat-attachments bucket so we
  -- don't need a new RLS surface; the path is `<userId>/vision/<uuid>.jpg`.
  bucket TEXT NOT NULL DEFAULT 'chat-attachments',
  storage_path TEXT NOT NULL,
  mime_type TEXT,
  size_bytes INTEGER,
  -- Optional user hint ('this is a receipt'). When set we skip
  -- classification and go straight to the matching extractor.
  hint_kind TEXT,
  -- Detected kind from the classifier. 'unknown' is the fallback —
  -- we still surface the OCR text so the user can copy it manually.
  detected_kind TEXT NOT NULL DEFAULT 'unknown'
    CHECK (detected_kind IN (
      'receipt', 'business_card', 'medication', 'whiteboard',
      'label', 'document', 'contract', 'inventory', 'unknown'
    )),
  classification_confidence NUMERIC,
  -- Per-kind structured extraction. Shape varies:
  --   receipt        { merchant, total, currency, date, line_items[], category }
  --   business_card  { name, email, phone, company, role, website, address }
  --   medication     { name, dose, frequency, schedule, prescriber, refill_date }
  --   whiteboard     { title, summary, bullets[] }
  --   label          { source_language, translation, target_language }
  extracted JSONB NOT NULL DEFAULT '{}'::jsonb,
  -- Plain text from OCR. Always populated when detection succeeds so
  -- the UI can fall back to "show me what you saw" even on unknowns.
  ocr_text TEXT,
  source_language TEXT,
  -- Lifecycle. The two-phase flow lets the user edit extracted fields
  -- before committing — important for receipts where amount accuracy
  -- matters.
  status TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN ('pending', 'classifying', 'extracted', 'committed', 'discarded', 'error')),
  error_message TEXT,
  -- Back-ref to the row this capture committed into.
  created_entity_kind TEXT,
  created_entity_id UUID,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS vision_captures_user_recent_idx
  ON public.vision_captures (user_id, created_at DESC);

CREATE INDEX IF NOT EXISTS vision_captures_user_active_idx
  ON public.vision_captures (user_id, status, updated_at DESC)
  WHERE status NOT IN ('committed', 'discarded');

CREATE OR REPLACE TRIGGER update_vision_captures_updated_at
  BEFORE UPDATE ON public.vision_captures
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ──────────────────────────────────────────────────────────────────────
-- 20260427110000_predictive_scheduler.sql
-- ──────────────────────────────────────────────────────────────────────

-- Predictive scheduler.
--
-- Builds on:
--   - tasks (priority, category, due_date)
--   - events (existing calendar slots)
--   - daily_checkins (energy_level, sleep_quality, mood)
--   - dori_task_stats (per-user category × hour-of-day completion stats)
--   - dori_slip_risk (open task → 0..1 risk score)
--
-- One new table + one view:
--   1. schedule_proposals — drafted weeks. blocks[] is JSONB so the
--      shape can evolve without schema churn. status lifecycle:
--        draft → reviewed → accepted | rejected | superseded
--   2. user_energy_profile view — per-user, per-hour-of-day average
--      energy from morning check-ins, with a sample-size column the
--      planner can use to weight confidence.

-- ============================================================
-- 1. schedule_proposals
-- ============================================================
CREATE TABLE IF NOT EXISTS public.schedule_proposals (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL,
  workspace_id UUID REFERENCES public.workspaces(id) ON DELETE SET NULL,
  -- ISO week start (Monday). Plus end_date so non-week ranges work.
  range_start DATE NOT NULL,
  range_end DATE NOT NULL,
  -- 'draft'   → just generated; user hasn't reviewed.
  -- 'reviewed' → user opened it.
  -- 'accepted' → user accepted some/all blocks (events created).
  -- 'rejected' → user dismissed without accepting any block.
  -- 'superseded' → a newer proposal replaced this one.
  status TEXT NOT NULL DEFAULT 'draft'
    CHECK (status IN ('draft', 'reviewed', 'accepted', 'rejected', 'superseded')),
  -- Each block:
  --   { id (uuid), date (YYYY-MM-DD), start_time (ISO), end_time (ISO),
  --     kind: 'deep'|'shallow'|'meeting'|'admin'|'break'|'errand',
  --     title, rationale, task_id?, event_id?, accepted (bool, default null),
  --     applied_event_id (uuid?), priority (high|medium|low) }
  blocks JSONB NOT NULL DEFAULT '[]'::jsonb,
  -- Free-form planner-side notes ("avoided 14:00 because last week
  -- you reported low energy at that hour").
  rationale TEXT,
  -- AI bookkeeping.
  model TEXT,
  generation_ms INTEGER,
  -- Snapshot of the inputs the planner saw, for debugging without
  -- re-running.
  input_snapshot JSONB NOT NULL DEFAULT '{}'::jsonb,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS schedule_proposals_user_recent_idx
  ON public.schedule_proposals (user_id, created_at DESC);

CREATE INDEX IF NOT EXISTS schedule_proposals_user_active_idx
  ON public.schedule_proposals (user_id, range_start DESC)
  WHERE status IN ('draft', 'reviewed', 'accepted');

CREATE OR REPLACE TRIGGER update_schedule_proposals_updated_at
  BEFORE UPDATE ON public.schedule_proposals
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ============================================================
-- 2. user_energy_profile view
-- ============================================================
-- Rolls up the last 60 days of MORNING check-ins into a single
-- per-user summary: average energy level (1=low, 2=medium, 3=high),
-- modal level, average sleep hours and quality. Sample size is
-- exposed so the planner can fall back to defaults when a user has
-- only checked in a few times.
--
-- Hour-of-day energy bands (morning / afternoon / evening) require
-- timestamped HealthKit data we don't have yet — that's a follow-up
-- once the Apple Health bridge populates a continuous signal.
CREATE OR REPLACE VIEW public.user_energy_profile AS
WITH levels AS (
  SELECT
    user_id,
    energy_level,
    -- 1 = low, 2 = medium, 3 = high. Other values get NULL.
    CASE energy_level
      WHEN 'high' THEN 3
      WHEN 'medium' THEN 2
      WHEN 'low' THEN 1
      ELSE NULL
    END AS energy_score,
    sleep_quality,
    sleep_hours,
    checkin_date
  FROM public.daily_checkins
  WHERE checkin_type = 'morning'
    AND checkin_date >= CURRENT_DATE - INTERVAL '60 days'
)
SELECT
  user_id,
  COUNT(*) FILTER (WHERE energy_score IS NOT NULL) AS sample_size,
  ROUND(AVG(energy_score) FILTER (WHERE energy_score IS NOT NULL)::numeric, 2) AS avg_energy,
  ROUND(AVG(sleep_quality)::numeric, 2) AS avg_sleep_quality,
  ROUND(AVG(sleep_hours)::numeric, 2) AS avg_sleep_hours,
  -- Most common reported level — useful as a tiebreaker.
  MODE() WITHIN GROUP (ORDER BY energy_level)
    FILTER (WHERE energy_level IS NOT NULL) AS modal_energy
FROM levels
GROUP BY user_id;

COMMENT ON VIEW public.user_energy_profile IS
  'Rolling 60-day morning-energy summary per user. Drives the predictive scheduler — schedule deep work into the user''s typical high-energy bands.';

