-- 20260427160000_cross_feature_wiring.sql
-- ──────────────────────────────────────────────────────────────────────

-- Cross-feature wiring.
--
-- Two existing-feature pairs that needed glue:
--
--   1. Subscription audit ↔ cancellation drafter:
--      The contracts table didn't track cancellation state, so the
--      "still charging" half of subscription_audit had no way to flip
--      true. Adds cancellation_drafts (audit log of every drafted
--      cancellation email), cancellation_requested_at (user clicked
--      "cancel"), and cancelled_at (user confirmed they sent it).
--
--   2. Trip → pack task:
--      The trip-prep flow needs a sentinel so the cron / on-demand
--      job is idempotent (won't duplicate the "Pack for X" task on
--      re-runs). Adds trips.prep_run_at + a generic metadata JSONB.

ALTER TABLE public.contracts
  ADD COLUMN IF NOT EXISTS cancellation_drafts JSONB
    NOT NULL DEFAULT '[]'::jsonb;

ALTER TABLE public.contracts
  ADD COLUMN IF NOT EXISTS cancellation_requested_at TIMESTAMPTZ;

ALTER TABLE public.contracts
  ADD COLUMN IF NOT EXISTS cancelled_at TIMESTAMPTZ;

-- Help the subscription_audit "ghost vs. still-charging" sort.
CREATE INDEX IF NOT EXISTS contracts_cancellation_pending_idx
  ON public.contracts (user_id, cancellation_requested_at DESC)
  WHERE cancellation_requested_at IS NOT NULL AND cancelled_at IS NULL;

ALTER TABLE public.trips
  ADD COLUMN IF NOT EXISTS prep_run_at TIMESTAMPTZ;

ALTER TABLE public.trips
  ADD COLUMN IF NOT EXISTS metadata JSONB
    NOT NULL DEFAULT '{}'::jsonb;

-- ──────────────────────────────────────────────────────────────────────
-- 20260427200000_ai_quotas.sql
-- ──────────────────────────────────────────────────────────────────────

-- AI cost ledger + per-user caps.
--
-- Builds on the existing `ai_usage` table (rows logged per AI call
-- with token counts + cost_estimate). Adds:
--
--   1. ai_quotas — per-user monthly cap. Defaults to a sane value
--                  for new users; operator can set per-user overrides.
--   2. ai_usage_monthly — view: per-user, per-calendar-month rollup
--                  of total cost and call count.
--   3. ai_usage_summary — view: per-user current-month rollup with
--                  headroom (cap minus spent), capacity_pct, and a
--                  `over_cap` boolean.
--   4. check_ai_quota() — RPC the edge functions call BEFORE making
--                  expensive AI calls. Returns { allowed, used_cents,
--                  cap_cents, headroom_pct, over_cap }.
--
-- The "current month" is bound by date_trunc('month', now()) so it
-- rolls automatically. Operators can implement per-week or per-day
-- caps later by changing the trunc target.

-- ============================================================
-- 1. ai_quotas
-- ============================================================
CREATE TABLE IF NOT EXISTS public.ai_quotas (
  user_id UUID NOT NULL PRIMARY KEY,
  -- Cap in cents (1/100 of a USD). NULL = use the default.
  monthly_cap_cents INTEGER,
  -- Operator-facing notes — useful for "this is the founders' cap" /
  -- "promotional bump for January" annotations.
  notes TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Default cap for users with no override row. Per ai_usage's existing
-- cost_estimate ($0.075/M input, $0.30/M output for Gemini Flash),
-- $5/month is roughly 60M input tokens — generous for normal use.
COMMENT ON COLUMN public.ai_quotas.monthly_cap_cents IS
  'Per-user monthly AI spend cap in cents. NULL falls back to the default (500 cents = $5).';

-- No user-level INSERT/UPDATE/DELETE — operators manage via service role.

CREATE OR REPLACE TRIGGER update_ai_quotas_updated_at
  BEFORE UPDATE ON public.ai_quotas
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ============================================================
-- 2. ai_usage_monthly view
-- ============================================================
CREATE OR REPLACE VIEW public.ai_usage_monthly AS
SELECT
  user_id,
  date_trunc('month', created_at)::date AS month,
  COUNT(*) AS calls,
  SUM(prompt_tokens) AS prompt_tokens,
  SUM(completion_tokens) AS completion_tokens,
  SUM(total_tokens) AS total_tokens,
  -- Round to whole cents for display; the underlying cost_estimate
  -- is fractional.
  ROUND((SUM(cost_estimate) * 100)::numeric, 2) AS cost_cents
FROM public.ai_usage
WHERE response_status = 'success'
GROUP BY user_id, date_trunc('month', created_at);

-- ============================================================
-- 3. ai_usage_summary view
-- ============================================================
-- Per-user CURRENT-MONTH rollup with cap headroom. RLS-friendly: uses
-- NULL /* TODO(auth-migration): was auth.uid() */ inside a CTE so the result auto-scopes when read by the
-- owning user.
CREATE OR REPLACE VIEW public.ai_usage_summary AS
WITH this_month AS (
  SELECT
    user_id,
    SUM(cost_estimate) AS spent_dollars,
    SUM(total_tokens) AS tokens,
    COUNT(*) AS calls
  FROM public.ai_usage
  WHERE created_at >= date_trunc('month', CURRENT_DATE)
    AND response_status = 'success'
  GROUP BY user_id
)
SELECT
  COALESCE(t.user_id, q.user_id) AS user_id,
  COALESCE(t.spent_dollars, 0) AS spent_dollars,
  COALESCE(ROUND(t.spent_dollars * 100, 2), 0) AS spent_cents,
  COALESCE(t.tokens, 0) AS tokens,
  COALESCE(t.calls, 0) AS calls,
  -- Default to 500 cents = $5/mo if no override.
  COALESCE(q.monthly_cap_cents, 500) AS cap_cents,
  -- Headroom = cap - spent, never negative.
  GREATEST(
    0,
    COALESCE(q.monthly_cap_cents, 500) - COALESCE(ROUND(t.spent_dollars * 100, 2), 0)
  ) AS headroom_cents,
  -- 0..100. Capped at 100 even when spend exceeds the cap so the
  -- progress bar maxes out.
  LEAST(
    100,
    GREATEST(
      0,
      ROUND((COALESCE(t.spent_dollars * 100, 0) / NULLIF(COALESCE(q.monthly_cap_cents, 500), 0)) * 100)
    )
  ) AS used_pct,
  COALESCE(ROUND(t.spent_dollars * 100, 2), 0) > COALESCE(q.monthly_cap_cents, 500) AS over_cap
FROM this_month t
FULL OUTER JOIN public.ai_quotas q ON q.user_id = t.user_id;

-- ============================================================
-- 4. check_ai_quota() RPC
-- ============================================================
-- Cheap pre-flight. Edge functions call this before expensive AI ops
-- and bail with a 429-equivalent if `allowed` is false.
CREATE OR REPLACE FUNCTION public.check_ai_quota(p_user_id UUID)
RETURNS TABLE (
  allowed BOOLEAN,
  used_cents NUMERIC,
  cap_cents INTEGER,
  headroom_cents NUMERIC,
  used_pct INTEGER,
  over_cap BOOLEAN
)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  WITH this_month AS (
    SELECT COALESCE(SUM(cost_estimate), 0) AS spent
      FROM public.ai_usage
     WHERE user_id = p_user_id
       AND response_status = 'success'
       AND created_at >= date_trunc('month', CURRENT_DATE)
  ),
  cap AS (
    SELECT COALESCE(monthly_cap_cents, 500) AS c
      FROM public.ai_quotas
     WHERE user_id = p_user_id
    UNION ALL SELECT 500 LIMIT 1
  )
  SELECT
    -- Allowed when spent < cap. Hard cut-off — no soft band.
    (ROUND(t.spent * 100, 2) < c.c) AS allowed,
    ROUND(t.spent * 100, 2) AS used_cents,
    c.c::int AS cap_cents,
    GREATEST(0, c.c - ROUND(t.spent * 100, 2)) AS headroom_cents,
    LEAST(100, GREATEST(0,
      ROUND((t.spent * 100 / NULLIF(c.c, 0)) * 100)::int
    )) AS used_pct,
    (ROUND(t.spent * 100, 2) > c.c) AS over_cap
  FROM this_month t, cap c
  LIMIT 1;
$$;

-- ──────────────────────────────────────────────────────────────────────
-- 20260427210000_encrypt_bank_tokens.sql
-- ──────────────────────────────────────────────────────────────────────

-- Encrypt Plaid access tokens at rest.
--
-- Drops the plaintext bank_connections.access_token column and
-- replaces it with access_token_ciphertext (text, base64 of AES-GCM
-- output). Encryption happens app-side in the plaid-exchange edge
-- function using BANK_TOKEN_SECRET (32-byte hex key, injected as a
-- Deno env var). Decryption happens in plaid-sync the same way.
--
-- Why app-side AES-GCM rather than pgsodium / pgcrypto?
--   - No need to add an extension; just one Deno secret.
--   - The DB never sees the key, so a leaked DB dump doesn't yield
--     usable tokens.
--   - Rotation: re-key by adding a new BANK_TOKEN_SECRET version,
--     leaving old ciphertext readable until next sync re-writes it.
--
-- Safe to drop the plaintext column because Plaid wasn't shipped to
-- production yet — there are no existing users to migrate. When
-- production users land later, run a re-link flow rather than try
-- to decrypt unknown plaintext.

ALTER TABLE public.bank_connections
  DROP COLUMN IF EXISTS access_token;

ALTER TABLE public.bank_connections
  ADD COLUMN IF NOT EXISTS access_token_ciphertext TEXT;

COMMENT ON COLUMN public.bank_connections.access_token_ciphertext IS
  'AES-GCM ciphertext of the Plaid access_token, base64-encoded. Encryption key is the BANK_TOKEN_SECRET edge-function secret. Format: base64(iv (12B) || ciphertext || tag (16B)). Plaintext never reaches the database.';

-- ──────────────────────────────────────────────────────────────────────
-- 20260427230000_workspace_rls_hardening.sql
-- ──────────────────────────────────────────────────────────────────────

-- Hardens RLS on tasks/events/notes/projects after the workspace foundation
-- migration (20260424210000). The original workspace INSERT/UPDATE/DELETE
-- policies used `workspace_id IS NULL OR is_workspace_member(workspace_id)`.
-- Postgres RLS combines permissive policies with OR, so the NULL branch made
-- it possible for any authenticated user to INSERT/UPDATE/DELETE rows owned
-- by other users as long as workspace_id was NULL — bypassing the personal
-- `NULL /* TODO(auth-migration): was auth.uid() */ = user_id` policies entirely.
--
-- This migration drops those policies and recreates them so they ONLY grant
-- access for actual workspace rows (workspace_id IS NOT NULL AND member),
-- and additionally pin user_id to the caller. Personal-data access continues
-- to flow through the original `Users can ... own ...` policies unchanged.

DO $$
DECLARE
  tbl text;
BEGIN
  FOREACH tbl IN ARRAY ARRAY['tasks', 'events', 'notes', 'projects']
  LOOP
    EXECUTE format('DROP POLICY IF EXISTS "Workspace members read %1$s"   ON public.%1$s', tbl);
    EXECUTE format('DROP POLICY IF EXISTS "Workspace members write %1$s"  ON public.%1$s', tbl);
    EXECUTE format('DROP POLICY IF EXISTS "Workspace members update %1$s" ON public.%1$s', tbl);
    EXECUTE format('DROP POLICY IF EXISTS "Workspace members delete %1$s" ON public.%1$s', tbl);
  END LOOP;
END $$;

-- The workspace UPDATE policies above intentionally let any workspace member
-- edit collaborative rows (that's the whole point of a shared workspace).
-- Without a guard, though, a member could UPDATE another member's row and
-- set user_id = NULL /* TODO(auth-migration): was auth.uid() */, then claim it as their own personal row through
-- the existing `Users can update own ...` policy. Lock user_id post-insert
-- with a trigger so collaborative editing stays open but ownership transfer
-- is impossible. Service-role calls bypass so server-side enrichers (data
-- migrations, support tooling) can still rewrite ownership when needed.

CREATE OR REPLACE FUNCTION public.lock_owner_user_id()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  IF current_setting('role', true) = 'service_role'
     OR 'authenticated' /* TODO(auth-migration): was auth.role() */ = 'service_role' THEN
    RETURN NEW;
  END IF;
  IF NEW.user_id IS DISTINCT FROM OLD.user_id THEN
    RAISE EXCEPTION '%.user_id is immutable', TG_TABLE_NAME;
  END IF;
  RETURN NEW;
END;
$$;

DO $$
DECLARE
  tbl text;
BEGIN
  FOREACH tbl IN ARRAY ARRAY['tasks', 'events', 'notes', 'projects']
  LOOP
    EXECUTE format('DROP TRIGGER IF EXISTS lock_owner_user_id_trg ON public.%I', tbl);
    EXECUTE format(
      'CREATE TRIGGER lock_owner_user_id_trg BEFORE UPDATE ON public.%I FOR EACH ROW EXECUTE FUNCTION public.lock_owner_user_id()',
      tbl
    );
  END LOOP;
END $$;

-- ──────────────────────────────────────────────────────────────────────
-- 20260427230500_lock_auto_actions_log_data.sql
-- ──────────────────────────────────────────────────────────────────────

-- The dori-execute-action edge function re-runs `action_data.tool_xml` from
-- auto_actions_log with the chat function's approval gate disabled. Users
-- have UPDATE rights on their own auto_actions_log rows (see migration
-- 20251226224801), which means a user could rewrite tool_xml between AI
-- generation and clicking Approve, then have the executor run the modified
-- tool unchecked. The "approve immutable proposal" UX contract was not
-- enforced at the data layer.
--
-- This trigger pins the immutable fields of an auto_actions_log row at
-- creation. Status, decision timestamps, and execution_result merged onto
-- action_data are still allowed to change; the original AI-generated body
-- (action_data.tool_xml plus action_type / function_name) is locked. The
-- service role bypasses row-level security but for clarity also bypasses
-- this trigger so server-side enrichers can rewrite the row freely.

CREATE OR REPLACE FUNCTION public.lock_auto_action_proposal()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  -- Service-role connections (cron, edge functions running with the service
  -- key) skip the lock. Authenticated end-user updates are constrained.
  IF current_setting('role', true) = 'service_role'
     OR 'authenticated' /* TODO(auth-migration): was auth.role() */ = 'service_role' THEN
    RETURN NEW;
  END IF;

  -- The proposal body is fixed at insert.
  IF NEW.action_type   IS DISTINCT FROM OLD.action_type   THEN
    RAISE EXCEPTION 'auto_actions_log.action_type is immutable';
  END IF;
  IF (NEW.action_data -> 'tool_xml') IS DISTINCT FROM (OLD.action_data -> 'tool_xml') THEN
    RAISE EXCEPTION 'auto_actions_log.action_data.tool_xml is immutable';
  END IF;
  IF (NEW.action_data -> 'function_name') IS DISTINCT FROM (OLD.action_data -> 'function_name') THEN
    RAISE EXCEPTION 'auto_actions_log.action_data.function_name is immutable';
  END IF;
  IF (NEW.action_data -> 'arguments') IS DISTINCT FROM (OLD.action_data -> 'arguments') THEN
    RAISE EXCEPTION 'auto_actions_log.action_data.arguments is immutable';
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS lock_auto_action_proposal_trg ON public.auto_actions_log;

CREATE OR REPLACE TRIGGER lock_auto_action_proposal_trg
  BEFORE UPDATE ON public.auto_actions_log
  FOR EACH ROW EXECUTE FUNCTION public.lock_auto_action_proposal();

-- ──────────────────────────────────────────────────────────────────────
-- 20260501103501_c4dda7c0-9fea-4e96-8d49-55f019792d3e.sql
-- ──────────────────────────────────────────────────────────────────────

-- Period tracking
CREATE TABLE IF NOT EXISTS public.period_logs (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  start_date DATE NOT NULL,
  end_date DATE,
  flow TEXT CHECK (flow IN ('light','medium','heavy')),
  symptoms TEXT[],
  notes TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX idx_period_logs_user_date ON public.period_logs(user_id, start_date DESC);

-- Fasting logs (Ramadan or general)
CREATE TABLE IF NOT EXISTS public.fasting_logs (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  fast_date DATE NOT NULL,
  fast_type TEXT NOT NULL DEFAULT 'ramadan',
  completed BOOLEAN NOT NULL DEFAULT true,
  notes TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (user_id, fast_date, fast_type)
);

-- Pantry inventory
CREATE TABLE IF NOT EXISTS public.pantry_items (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  item TEXT NOT NULL,
  quantity NUMERIC,
  unit TEXT,
  category TEXT,
  expires_on DATE,
  notes TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX idx_pantry_user ON public.pantry_items(user_id);

-- Flight tracking
CREATE TABLE IF NOT EXISTS public.flight_tracking (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  trip_event_id UUID,
  flight_number TEXT NOT NULL,
  airline TEXT,
  origin TEXT,
  destination TEXT,
  depart_at TIMESTAMPTZ NOT NULL,
  checkin_reminder_at TIMESTAMPTZ,
  status TEXT,
  notes TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX idx_flights_user_date ON public.flight_tracking(user_id, depart_at);

-- Presence status (visible to space members)
CREATE TABLE IF NOT EXISTS public.presence_status (
  user_id UUID NOT NULL PRIMARY KEY REFERENCES public.users(id) ON DELETE CASCADE,
  status TEXT NOT NULL DEFAULT 'home',
  message TEXT,
  expires_at TIMESTAMPTZ,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Email snoozed (provider-agnostic)
CREATE TABLE IF NOT EXISTS public.email_snoozed (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  provider TEXT NOT NULL DEFAULT 'gmail',
  external_id TEXT NOT NULL,
  subject TEXT,
  snooze_until TIMESTAMPTZ NOT NULL,
  resurfaced BOOLEAN NOT NULL DEFAULT false,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE (user_id, provider, external_id)
);

CREATE INDEX idx_email_snoozed_due ON public.email_snoozed(user_id, snooze_until) WHERE resurfaced = false;

-- Task enrichments
ALTER TABLE public.tasks ADD COLUMN IF NOT EXISTS estimate_minutes INTEGER;

ALTER TABLE public.tasks ADD COLUMN IF NOT EXISTS completion_note TEXT;

ALTER TABLE public.tasks ADD COLUMN IF NOT EXISTS tags TEXT[] DEFAULT '{}';

CREATE INDEX IF NOT EXISTS idx_tasks_tags ON public.tasks USING GIN(tags);

-- updated_at triggers where needed
CREATE OR REPLACE TRIGGER trg_period_logs_updated BEFORE UPDATE ON public.period_logs FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

CREATE OR REPLACE TRIGGER trg_pantry_updated BEFORE UPDATE ON public.pantry_items FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

CREATE OR REPLACE TRIGGER trg_flights_updated BEFORE UPDATE ON public.flight_tracking FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

CREATE OR REPLACE TRIGGER trg_presence_updated BEFORE UPDATE ON public.presence_status FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

