-- ──────────────────────────────────────────────────────────────────────
-- 20260515000000_refresh_auto_actions_log_schema.sql
-- ──────────────────────────────────────────────────────────────────────

-- Re-assert the columns the chat / telegram surfaces write to on
-- auto_actions_log, and force PostgREST to reload its schema cache.
--
-- Symptom that prompted this:
--   chat function -> insert into auto_actions_log -> PostgREST returned
--   "Could not find the 'expires_at' column of 'auto_actions_log' in the
--   schema cache", which surfaces in Telegram as "Could not queue: ...".
--
-- expires_at, source and source_ref were added by earlier migrations
-- (20260424120000_dori_action_confirmations and 20260424180000_dori_telegram_richer_ux),
-- but PostgREST's in-memory schema cache can outlive an ALTER TABLE if the
-- migration ran without a cache-reload signal. The ADD COLUMN IF NOT EXISTS
-- statements below are no-ops if the columns are already present; the NOTIFY
-- at the bottom is the actual fix for the reported error.

ALTER TABLE public.auto_actions_log
  ADD COLUMN IF NOT EXISTS source text NOT NULL DEFAULT 'web',
  ADD COLUMN IF NOT EXISTS source_ref text,
  ADD COLUMN IF NOT EXISTS expires_at timestamptz;

-- Tell PostgREST to reload its schema cache so the newly-visible columns
-- become writable through the REST API immediately.
NOTIFY pgrst, 'reload schema';

-- ──────────────────────────────────────────────────────────────────────
-- 20260515183000_refresh_dori_plans_schema.sql
-- ──────────────────────────────────────────────────────────────────────

-- Refresh PostgREST's schema cache so the dori_create_plan RPC (and any
-- other functions added since the last reload) are reachable through
-- supabase.rpc(...).
--
-- Symptom that prompted this:
--   chat function -> supabase.rpc('dori_create_plan', { ... }) returned
--   "Could not find the function public.dori_create_plan(...) in the
--   schema cache", surfaced in Telegram as
--   "Plan create failed: Could not find the function ...".
--
-- The function itself is defined in 20260426170000_dori_action_plans and
-- granted to authenticated + service_role. PostgREST's in-memory cache
-- just hadn't been told to reload after that migration ran (same root
-- cause as the auto_actions_log.expires_at miss).
--
-- NOTIFY is global; it refreshes every table + function in one shot.

NOTIFY pgrst, 'reload schema';

-- ──────────────────────────────────────────────────────────────────────
-- 20260516120000_recurrence_exceptions_and_focus_sessions.sql
-- ──────────────────────────────────────────────────────────────────────

-- Round-2 audit follow-ups.
--
-- 1) recurrence_exceptions: lets a user skip individual occurrences of a
--    recurring task/event without rewriting the RRULE. The chat function
--    expands occurrences by reading recurrence_rule (FREQ/BYDAY/UNTIL) and
--    filtering out any (parent_id, exception_date) pair in this table.
--    Backed by a manage_exception tool that the AI emits for phrases like
--    "skip next Tuesday" or "cancel this Wednesday's class".
--
-- 2) focus_sessions: time-tracking. A row per focus block; the manage_focus
--    tool starts/stops sessions and aggregates "how much time on X this
--    week". An open session has ended_at NULL — only one open session per
--    user at a time (enforced via a partial unique index, not a check
--    constraint, because PostgreSQL CHECK can't reference COUNT()).

CREATE TABLE IF NOT EXISTS public.recurrence_exceptions (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id uuid NOT NULL,
  -- 'task' or 'event'. We don't FK to either table because the parent row
  -- can disappear (delete) without dragging exceptions along; the foreign
  -- side is cleaned up by a periodic sweeper.
  parent_kind text NOT NULL CHECK (parent_kind IN ('task', 'event')),
  parent_id uuid NOT NULL,
  -- The local-date of the skipped occurrence (YYYY-MM-DD in the user's tz).
  -- Stored as date so a single value covers both task-due-on-day and
  -- event-starting-on-day. Multi-day events still match on their start day.
  exception_date date NOT NULL,
  reason text,
  created_at timestamptz NOT NULL DEFAULT now(),
  UNIQUE (parent_kind, parent_id, exception_date)
);

CREATE INDEX IF NOT EXISTS recurrence_exceptions_user_idx
  ON public.recurrence_exceptions (user_id, parent_kind, parent_id);

DROP TABLE IF EXISTS public.focus_sessions CASCADE;

CREATE TABLE IF NOT EXISTS public.focus_sessions (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id uuid NOT NULL,
  task_id uuid REFERENCES public.tasks(id) ON DELETE SET NULL,
  -- Free-text label for sessions not tied to a specific task ("deep work
  -- on Q3 plan"). NULL when task_id is set, since the task title covers
  -- it; either label or task_id must be present (enforced in the tool
  -- handler so we don't reject historic backfills).
  label text,
  category text NOT NULL DEFAULT 'personal'
    CHECK (category IN ('business', 'personal', 'family', 'shared', 'focus')),
  started_at timestamptz NOT NULL DEFAULT now(),
  ended_at timestamptz,
  duration_minutes integer GENERATED ALWAYS AS (
    CASE
      WHEN ended_at IS NULL THEN NULL
      ELSE GREATEST(0, FLOOR(EXTRACT(EPOCH FROM (ended_at - started_at)) / 60)::integer)
    END
  ) STORED,
  workspace_id uuid,
  created_at timestamptz NOT NULL DEFAULT now()
);

-- At most one open (ended_at IS NULL) session per user. Partial unique
-- index is the postgres-idiomatic way to express "only one row matching
-- this predicate may exist per user".
CREATE UNIQUE INDEX IF NOT EXISTS focus_sessions_one_open_per_user
  ON public.focus_sessions (user_id) WHERE ended_at IS NULL;

CREATE INDEX IF NOT EXISTS focus_sessions_user_time_idx
  ON public.focus_sessions (user_id, started_at DESC);

CREATE INDEX IF NOT EXISTS focus_sessions_task_idx
  ON public.focus_sessions (task_id) WHERE task_id IS NOT NULL;

-- 3) telegram_documents: a per-user cache of the latest document the user
--    uploaded via Telegram. The summarise_document tool pulls extracted_text
--    from here rather than re-downloading on every turn (Telegram file_ids
--    are also short-lived). One row replaces the previous on each upload —
--    we don't keep history, since the user only ever refers to "the doc I
--    just sent".

CREATE TABLE IF NOT EXISTS public.telegram_documents (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id uuid NOT NULL UNIQUE,
  filename text NOT NULL,
  mime_type text NOT NULL,
  size_bytes integer,
  -- Plain-text extraction. For PDFs this is the page text; for text/* it's
  -- the body as-is. Hard-capped server-side before insert.
  extracted_text text,
  created_at timestamptz NOT NULL DEFAULT now()
);

-- PostgREST cache pickup.
NOTIFY pgrst, 'reload schema';

-- ──────────────────────────────────────────────────────────────────────
-- 20260517090000_symptom_logs_and_anniversary.sql
-- ──────────────────────────────────────────────────────────────────────

-- Round-3 audit follow-ups.
--
-- 1) symptom_logs: track a single symptom across multiple days so the
--    bot can answer "headache day 3" or "how long has my throat hurt?".
--    Distinct from wellbeing_logs (one row per checkin) — this is a
--    continuous symptom thread keyed by (user, symptom).
--
-- 2) family_members.anniversary_date: mirror of birth_date so the same
--    yearly-event-plus-prep-task chain that powers birthdays works for
--    weddings, work-iversaries, etc.

CREATE TABLE IF NOT EXISTS public.symptom_logs (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id uuid NOT NULL,
  symptom text NOT NULL,
  severity smallint CHECK (severity BETWEEN 1 AND 10),
  notes text,
  -- Day this entry is for. Defaults to today in UTC; the tool handler
  -- can override with the user's local date.
  log_date date NOT NULL DEFAULT (now() AT TIME ZONE 'UTC')::date,
  created_at timestamptz NOT NULL DEFAULT now(),
  -- One row per (user, symptom, day) so re-logging the same symptom
  -- the same day upserts rather than creating duplicates.
  UNIQUE (user_id, symptom, log_date)
);

CREATE INDEX IF NOT EXISTS symptom_logs_user_symptom_idx
  ON public.symptom_logs (user_id, symptom, log_date DESC);

ALTER TABLE public.family_members
  ADD COLUMN IF NOT EXISTS anniversary_date date;

COMMENT ON COLUMN public.family_members.anniversary_date IS
  'Wedding / partnership / work anniversary. Birthdays live on birth_date — this is the other yearly milestone.';

NOTIFY pgrst, 'reload schema';

